const minimal_jp2_codestream = [_]u8{
    0xff, 0x4f, // SOC
    0xff, 0x51, // SIZ
    0x00, 0x2f, // Lsiz
    0x00, 0x00, // Rsiz
    0x00, 0x00, 0x00, 0x02, // Xsiz
    0x00, 0x00, 0x00, 0x01, // Ysiz
    0x00, 0x00, 0x00, 0x00, // XOsiz
    0x00, 0x00, 0x00, 0x00, // YOsiz
    0x00, 0x00, 0x00, 0x02, // XTsiz
    0x00, 0x00, 0x00, 0x01, // YTsiz
    0x00, 0x00, 0x00, 0x00, // XTOsiz
    0x00, 0x00, 0x00, 0x00, // YTOsiz
    0x00, 0x03, // Csiz
    0x07, 0x01,
    0x01, 0x07,
    0x01, 0x01,
    0x07, 0x01,
    0x01,
    0xff, 0xd9, // EOC
};

test "5/3 wavelet roundtrips integer-like samples" {
    const allocator = std.testing.allocator;
    const width = 5;
    const height = 4;

    var data = [_]f32{
        10, 11, 12, 13, 14,
        20, 21, 22, 23, 24,
        30, 31, 32, 33, 34,
        40, 41, 42, 43, 44,
    };
    const original = data;

    const levels = try wavelet.forward2D(
        allocator,
        data[0..],
        width,
        height,
        3,
        .reversible_5_3,
    );
    try wavelet.inverse2D(allocator, data[0..], width, height, levels, .reversible_5_3);

    for (data, original) |actual, expected| {
        try std.testing.expectApproxEqAbs(expected, actual, 0.001);
    }
}

test "SIMD lane policy is a supported power-of-two width" {
    try std.testing.expect(simd.i32_lanes == 4 or simd.i32_lanes == 8 or simd.i32_lanes == 16);
    try std.testing.expect((simd.i32_lanes & (simd.i32_lanes - 1)) == 0);
    try std.testing.expectEqual(@as(comptime_int, 2), simd.f32_pair_lanes);
    try std.testing.expect(simd.family.len > 0);
}

test "T2 packet header presence bit matches temporary envelope bytes" {
    const allocator = std.testing.allocator;
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);

    try t2.appendPacketPresenceHeader(allocator, &out, false);
    try t2.appendPacketPresenceHeader(allocator, &out, true);

    try std.testing.expectEqualSlices(u8, &[_]u8{ 0x00, 0x80 }, out.items);

    var cursor: usize = 0;
    try std.testing.expect(!try t2.readPacketPresenceHeader(out.items, &cursor, out.items.len));
    try std.testing.expectEqual(@as(usize, 1), cursor);
    try std.testing.expect(try t2.readPacketPresenceHeader(out.items, &cursor, out.items.len));
    try std.testing.expectEqual(out.items.len, cursor);
}

test "ISO MQ encoder flushes an empty code-block segment" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 1);
    defer encoder.deinit();

    const bytes = try encoder.finish();
    defer allocator.free(bytes);

    try std.testing.expectEqualSlices(u8, &[_]u8{ 0xff, 0x7f }, bytes);
}

test "ISO MQ encoder byteout keeps marker prefixes stuffed" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 1);
    defer encoder.deinit();

    var index: usize = 0;
    while (index < 512) : (index += 1) {
        try encoder.write(0, index % 3 == 0);
    }
    const bytes = try encoder.finish();
    defer allocator.free(bytes);

    var byte_index: usize = 1;
    while (byte_index < bytes.len) : (byte_index += 1) {
        if (bytes[byte_index - 1] == 0xff) {
            try std.testing.expect((bytes[byte_index] & 0x80) == 0);
        }
    }
}

test "ISO MQ encoder resetStream preserves deterministic output" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 2);
    defer encoder.deinit();

    for (0..64) |index| {
        try encoder.write(index % 2, index % 5 == 0);
    }
    const first = try encoder.finish();
    defer allocator.free(first);

    encoder.resetStream();
    encoder.resetContexts();
    for (0..64) |index| {
        try encoder.write(index % 2, index % 5 == 0);
    }
    const second = try encoder.finish();
    defer allocator.free(second);

    try std.testing.expectEqualSlices(u8, first, second);
}

fn ertermDecisionContext(index: usize) usize {
    return (index * 3 + index / 5) % 4;
}

fn ertermDecisionBit(index: usize) bool {
    return ((index * 11 + 7) % 17) < 6;
}

test "ISO MQ ER-TERM flush roundtrips encoded decisions" {
    const allocator = std.testing.allocator;
    // Several lengths so the flush hits different ct phases.
    inline for (.{ 5, 17, 96, 353 }) |count| {
        var encoder = try mq_iso.Encoder.init(allocator, 4);
        defer encoder.deinit();

        var contexts: [count]usize = undefined;
        var bits: [count]bool = undefined;
        for (0..count) |index| {
            contexts[index] = ertermDecisionContext(index);
            bits[index] = ertermDecisionBit(index);
            try encoder.write(contexts[index], bits[index]);
        }
        const bytes = try encoder.finishErterm();
        defer allocator.free(bytes);

        var decoder = try mq_iso.Decoder.init(allocator, 4, bytes);
        defer decoder.deinit();
        for (contexts, bits) |context, bit| {
            try std.testing.expectEqual(bit, try decoder.read(context));
        }
    }
}

test "ISO MQ ER-TERM flush matches interop-verified byte vectors" {
    // Golden regression lock for the D.4.2 ER-TERM flush. These vectors were
    // captured from the same encoder whose full-image ERTERM output kdu_expand,
    // OpenJPEG, and Grok decode pixel-exactly (docs/next_steps.md interop pass),
    // so the exact bytes are normative. A refactor of finishActiveStreamErterm
    // that silently changes them will fail here in CI instead of only in the
    // out-of-CI interop_erterm.ps1 gate. Each vector is also decoded back to
    // confirm self-consistency.
    const allocator = std.testing.allocator;
    const Vector = struct { count: usize, bytes: []const u8 };
    const vectors = [_]Vector{
        .{ .count = 5, .bytes = &.{0x40} },
        .{ .count = 40, .bytes = &.{ 0x45, 0xa4, 0xeb, 0x4d, 0xf1, 0xa9 } },
        .{ .count = 96, .bytes = &.{ 0x45, 0xa4, 0xeb, 0x4d, 0xf1, 0xb3, 0x9d, 0xe6, 0xcd, 0xf8, 0x95, 0x10, 0x78 } },
    };
    for (vectors) |vector| {
        errdefer std.debug.print("ERTERM golden vector count={} failed\n", .{vector.count});
        var encoder = try mq_iso.Encoder.init(allocator, 4);
        defer encoder.deinit();
        for (0..vector.count) |index| {
            try encoder.write(ertermDecisionContext(index), ertermDecisionBit(index));
        }
        const bytes = try encoder.finishErterm();
        defer allocator.free(bytes);
        try std.testing.expectEqualSlices(u8, vector.bytes, bytes);

        var decoder = try mq_iso.Decoder.init(allocator, 4, bytes);
        defer decoder.deinit();
        for (0..vector.count) |index| {
            try std.testing.expectEqual(ertermDecisionBit(index), try decoder.read(ertermDecisionContext(index)));
        }
    }
}

test "ISO MQ decoder roundtrips encoded decisions" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 4);
    defer encoder.deinit();

    var contexts: [96]usize = undefined;
    var bits: [96]bool = undefined;
    for (0..contexts.len) |index| {
        contexts[index] = (index * 3 + index / 5) % 4;
        bits[index] = ((index * 11 + 7) % 17) < 6;
        try encoder.write(contexts[index], bits[index]);
    }
    const bytes = try encoder.finish();
    defer allocator.free(bytes);

    var decoder = try mq_iso.Decoder.init(allocator, 4, bytes);
    defer decoder.deinit();
    for (contexts, bits) |context, bit| {
        try std.testing.expectEqual(bit, try decoder.read(context));
    }
}

test "ISO MQ profiled decoder matches unchecked decisions and accounts branches" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 5);
    defer encoder.deinit();

    var contexts: [160]usize = undefined;
    var bits: [160]bool = undefined;
    for (0..contexts.len) |index| {
        contexts[index] = (index * 7 + index / 3) % 5;
        bits[index] = ((index * 13 + 5) % 19) < 8;
        try encoder.write(contexts[index], bits[index]);
    }
    const bytes = try encoder.finish();
    defer allocator.free(bytes);

    var unchecked = try mq_iso.Decoder.init(allocator, 5, bytes);
    defer unchecked.deinit();
    var profiled = try mq_iso.Decoder.init(allocator, 5, bytes);
    defer profiled.deinit();

    var stats = mq_iso.DecodeBranchStats{};
    for (contexts, bits) |context, bit| {
        try std.testing.expectEqual(bit, unchecked.readUnchecked(context));
        try std.testing.expectEqual(bit, profiled.readProfiled(context, &stats));
    }

    try std.testing.expectEqual(
        @as(u64, contexts.len),
        stats.fast_mps + stats.lps + stats.renorm_mps,
    );
}

test "ISO MQ decoder context reset mirrors encoder reset" {
    const allocator = std.testing.allocator;
    var encoder = try mq_iso.Encoder.init(allocator, 2);
    defer encoder.deinit();

    for (0..32) |index| {
        try encoder.write(index % 2, index % 7 == 0);
    }
    encoder.resetContexts();
    for (0..32) |index| {
        try encoder.write(index % 2, index % 5 == 0);
    }
    const bytes = try encoder.finish();
    defer allocator.free(bytes);

    var decoder = try mq_iso.Decoder.init(allocator, 2, bytes);
    defer decoder.deinit();
    for (0..32) |index| {
        try std.testing.expectEqual(index % 7 == 0, try decoder.read(index % 2));
    }
    decoder.resetContexts();
    for (0..32) |index| {
        try std.testing.expectEqual(index % 5 == 0, try decoder.read(index % 2));
    }
}

test "ISO MQ decoder reinitStream resets cached byte state" {
    const allocator = std.testing.allocator;
    var first_encoder = try mq_iso.Encoder.init(allocator, 3);
    defer first_encoder.deinit();
    var second_encoder = try mq_iso.Encoder.init(allocator, 3);
    defer second_encoder.deinit();

    var contexts: [96]usize = undefined;
    var first_bits: [96]bool = undefined;
    var second_bits: [96]bool = undefined;
    for (0..contexts.len) |index| {
        contexts[index] = (index * 5 + index / 7) % 3;
        first_bits[index] = ((index * 11 + 3) % 23) < 9;
        second_bits[index] = ((index * 17 + 1) % 29) < 11;
        try first_encoder.write(contexts[index], first_bits[index]);
        try second_encoder.write(contexts[index], second_bits[index]);
    }

    const first_bytes = try first_encoder.finish();
    defer allocator.free(first_bytes);
    const second_bytes = try second_encoder.finish();
    defer allocator.free(second_bytes);

    var decoder = try mq_iso.Decoder.init(allocator, 3, first_bytes);
    defer decoder.deinit();
    for (contexts, first_bits) |context, bit| {
        try std.testing.expectEqual(bit, try decoder.read(context));
    }

    decoder.resetContexts();
    decoder.reinitStream(second_bytes);
    for (contexts, second_bits) |context, bit| {
        try std.testing.expectEqual(bit, try decoder.read(context));
    }
}

test "T2 packet header bitstream inserts marker-safe stuff bits after 0xff" {
    const allocator = std.testing.allocator;
    var out = std.ArrayList(u8).empty;
    defer out.deinit(allocator);

    var writer = t2.PacketHeaderWriter.init(allocator, &out);
    try writer.writeBits(0xff, 8);
    try writer.writeBit(true);
    try writer.finish();

    try std.testing.expectEqualSlices(u8, &[_]u8{ 0xff, 0x40 }, out.items);

    var reader = t2.PacketHeaderReader.init(out.items);
    var bit_count: usize = 0;
    while (bit_count < 9) : (bit_count += 1) {
        try std.testing.expect(try reader.readBit());
    }
    try reader.byteAlign();
    try std.testing.expectEqual(out.items.len, reader.bytesConsumed());
}

