test "T2 coding pass count coder roundtrips ISO packet header ranges" {
    const allocator = std.testing.allocator;
    const pass_counts = [_]u16{ 1, 2, 3, 5, 6, 36, 37, 164 };
    const Vector = struct {
        passes: u16,
        bytes: []const u8,
    };
    const vectors = [_]Vector{
        .{ .passes = 1, .bytes = &.{0x00} },
        .{ .passes = 2, .bytes = &.{0x80} },
        .{ .passes = 3, .bytes = &.{0xc0} },
        .{ .passes = 5, .bytes = &.{0xe0} },
        .{ .passes = 6, .bytes = &.{ 0xf0, 0x00 } },
        .{ .passes = 36, .bytes = &.{ 0xff, 0x00 } },
        .{ .passes = 37, .bytes = &.{ 0xff, 0x40, 0x00 } },
        .{ .passes = 164, .bytes = &.{ 0xff, 0x7f, 0x80 } },
    };

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(allocator);
    var writer = t2.PacketHeaderWriter.init(allocator, &bytes);
    for (pass_counts) |pass_count| {
        try t2.writeCodingPassCount(&writer, pass_count);
    }
    try writer.finish();

    var reader = t2.PacketHeaderReader.init(bytes.items);
    for (pass_counts) |pass_count| {
        try std.testing.expectEqual(pass_count, try t2.readCodingPassCount(&reader));
    }
    try reader.byteAlign();
    try std.testing.expectEqual(bytes.items.len, reader.bytesConsumed());
    try std.testing.expectError(t2.PacketHeaderError.InvalidPacketHeader, t2.writeCodingPassCount(&writer, 0));
    try std.testing.expectError(t2.PacketHeaderError.InvalidPacketHeader, t2.writeCodingPassCount(&writer, 165));

    for (vectors) |vector| {
        bytes.clearRetainingCapacity();
        var vector_writer = t2.PacketHeaderWriter.init(allocator, &bytes);
        try t2.writeCodingPassCount(&vector_writer, vector.passes);
        try vector_writer.finish();
        try std.testing.expectEqualSlices(u8, vector.bytes, bytes.items);
    }
}

test "T2 terminated packet header rejects segment counts above table capacity" {
    const allocator = std.testing.allocator;

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(allocator);
    var writer = t2.PacketHeaderWriter.init(allocator, &bytes);
    try writer.writeBit(true); // previously included block remains included
    try t2.writeCodingPassCount(&writer, ebcot.max_block_segments + 1);
    try writer.finish();

    const cases = [_]struct {
        label: []const u8,
        bypass: bool,
        terminate_all: bool,
    }{
        .{ .label = "TERMALL", .bypass = false, .terminate_all = true },
        .{ .label = "BYPASS+TERMALL", .bypass = true, .terminate_all = true },
    };

    for (cases) |case| {
        errdefer std.debug.print("terminated packet-header segment-count case failed: {s}\n", .{case.label});
        var reader = t2.PacketHeaderReader.init(bytes.items);
        var inclusion = try t2.TagTreeDecoder.init(allocator, 1, 1);
        defer inclusion.deinit();
        var zero_bitplanes = try t2.TagTreeDecoder.init(allocator, 1, 1);
        defer zero_bitplanes.deinit();
        var length_state = t2.SegmentLengthState{};

        try std.testing.expectError(
            t2.PacketHeaderError.InvalidPacketHeader,
            t2.readCodeBlockPacketHeader(
                &reader,
                &inclusion,
                &zero_bitplanes,
                &length_state,
                0,
                0,
                0,
                true,
                0,
                case.bypass,
                case.terminate_all,
                0,
            ),
        );
    }
}

test "T2 segment length coder preserves Lblock state" {
    const allocator = std.testing.allocator;
    const Segment = struct {
        passes: u16,
        bytes: u64,
    };
    const segments = [_]Segment{
        .{ .passes = 1, .bytes = 7 },
        .{ .passes = 1, .bytes = 8 },
        .{ .passes = 6, .bytes = 63 },
        .{ .passes = 37, .bytes = 1024 },
    };

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(allocator);
    var writer = t2.PacketHeaderWriter.init(allocator, &bytes);
    var write_state = t2.SegmentLengthState{};
    for (segments) |segment| {
        try write_state.write(&writer, segment.passes, segment.bytes);
    }
    try writer.finish();

    var reader = t2.PacketHeaderReader.init(bytes.items);
    var read_state = t2.SegmentLengthState{};
    for (segments) |segment| {
        try std.testing.expectEqual(segment.bytes, try read_state.read(&reader, segment.passes));
    }
    try reader.byteAlign();
    try std.testing.expectEqual(write_state.lblock, read_state.lblock);
    try std.testing.expectEqual(bytes.items.len, reader.bytesConsumed());
    try std.testing.expectError(t2.PacketHeaderError.InvalidPacketHeader, write_state.write(&writer, 0, 1));
}

test "T2 multi-segment length coder preserves zero-byte terminated segments" {
    const allocator = std.testing.allocator;
    const segments = [_]t2.SegmentSpan{
        .{ .pass_count = 1, .byte_length = 2 },
        .{ .pass_count = 1, .byte_length = 0 },
        .{ .pass_count = 1, .byte_length = 5 },
        .{ .pass_count = 1, .byte_length = 0 },
        .{ .pass_count = 1, .byte_length = 33 },
    };

    var bytes = std.ArrayList(u8).empty;
    defer bytes.deinit(allocator);
    var writer = t2.PacketHeaderWriter.init(allocator, &bytes);
    var write_state = t2.SegmentLengthState{};
    try write_state.writeSegments(&writer, segments[0..]);
    try writer.finish();

    var pass_counts = [_]u16{1} ** segments.len;
    var lengths: [segments.len]u64 = undefined;
    var reader = t2.PacketHeaderReader.init(bytes.items);
    var read_state = t2.SegmentLengthState{};
    const total = try read_state.readSegments(&reader, pass_counts[0..], lengths[0..]);
    try reader.byteAlign();

    var expected_total: u64 = 0;
    for (segments, lengths) |segment, length| {
        try std.testing.expectEqual(segment.byte_length, length);
        expected_total += segment.byte_length;
    }
    try std.testing.expectEqual(expected_total, total);
    try std.testing.expectEqual(write_state.lblock, read_state.lblock);
    try std.testing.expectEqual(bytes.items.len, reader.bytesConsumed());
}

