    const input = image.Image{
        .allocator = allocator,
        .width = 4,
        .height = 4,
        .pixels = pixels,
    };

    const encoded = try codec.encodeImage(allocator, input, .{
        .wavelet = .reversible_5_3,
        .levels = 2,
        .quant_step = 1.0,
    });
