}

test "parallel 5/3 DWT matches the serial workspace transform byte-for-byte" {
    const allocator = std.testing.allocator;
    // Cover vector-group sizes, scalar tails, odd dims, and several worker
    // counts (1 = inline fallback, up to more workers than columns).
    const dims = [_][2]usize{ .{ 64, 64 }, .{ 65, 63 }, .{ 129, 128 }, .{ 100, 40 }, .{ 17, 200 }, .{ 512, 512 } };
    const thread_counts = [_]usize{ 1, 2, 4, 8, 16 };

    for (dims) |dim| {
        const width = dim[0];
        const height = dim[1];
        const pixels = width * height;

        var serial: [3][]i32 = undefined;
        var parallel: [3][]i32 = undefined;
        for (0..3) |c| {
            serial[c] = try allocator.alloc(i32, pixels);
            parallel[c] = try allocator.alloc(i32, pixels);
        }
        defer for (0..3) |c| {
            allocator.free(serial[c]);
            allocator.free(parallel[c]);
        };

        for (thread_counts) |threads| {
            var seed: u32 = @intCast(width * 2749 + height * 40961 + threads * 7);
            for (0..3) |c| {
                for (serial[c], 0..) |*sample, index| {
                    seed = seed *% 1664525 +% 1013904223;
                    sample.* = @as(i32, @intCast((seed >> 13) & 0x3ff)) - 512 +
                        @as(i32, @intCast(index % 23)) - 11;
                }
                @memcpy(parallel[c], serial[c]);
            }

            // Serial reference: one workspace transform per component.
            var workspace = try wavelet_int.Workspace.init(allocator, @max(width, height));
            defer workspace.deinit();
            var serial_levels: u8 = 0;
            for (0..3) |c| {
                serial_levels = try wavelet_int.forward53WithWorkspace(&workspace, serial[c], width, height, 6);
            }

            const parallel_levels = try wavelet_int.forward53Parallel(allocator, parallel, width, height, 6, threads);
            try std.testing.expectEqual(serial_levels, parallel_levels);
            for (0..3) |c| try std.testing.expectEqualSlices(i32, serial[c], parallel[c]);

            // Inverse must also match and restore the input.
            for (0..3) |c| {
                try wavelet_int.inverse53WithWorkspace(&workspace, serial[c], width, height, serial_levels);
            }
            try wavelet_int.inverse53Parallel(allocator, parallel, width, height, parallel_levels, threads);
            for (0..3) |c| try std.testing.expectEqualSlices(i32, serial[c], parallel[c]);
        }
    }
}

test "odd and edge dimensions roundtrip losslessly through archival encode/decode" {
    const allocator = std.testing.allocator;
    // Odd, thin, and minimal geometries stress the 5/3 DWT edge lifting
    // (odd lowCount), sub-band/precinct/code-block edge derivation, and the
    // resolution clamp on tiny dimensions. Each was also confirmed to decode
    // losslessly through OpenJPEG 2.5.4 and Grok 20.3.6.
    const dims = [_][2]usize{
        .{ 1, 1 },   .{ 5, 5 },   .{ 17, 13 }, .{ 3, 100 },   .{ 100, 3 },
        .{ 255, 1 }, .{ 33, 31 }, .{ 63, 65 }, .{ 127, 129 }, .{ 2, 2 },
    };
    for (dims) |d| {
        errdefer std.debug.print("odd-dimension roundtrip failed at {}x{}\n", .{ d[0], d[1] });
        const w = d[0];
        const h = d[1];
        const samples = try allocator.alloc(u16, w * h * 3);
        defer allocator.free(samples);
        var seed: u32 = @intCast(w * 6151 + h * 389 + 7);
        for (samples) |*s| {
            seed = seed *% 1664525 +% 1013904223;
            s.* = @intCast((seed >> 15) & 0xff);
        }
        const rgb = image.RgbImage{ .allocator = allocator, .width = w, .height = h, .bit_depth = 8, .samples = samples };

        // Archival framing (SOP+EPH+TLM) plus a request for more resolution
        // levels than tiny dimensions can supply, so the clamp path runs too.
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
            .levels = 3,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer allocator.free(bytes);

        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        try std.testing.expectEqual(w, decoded.width);
        try std.testing.expectEqual(h, decoded.height);
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

        // The JP2 wrapper accepts the odd-geometry codestream.
        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
        defer allocator.free(wrapped);
        _ = try jp2.parseInfo(wrapped);
    }
}

test "16-bit RGB roundtrips losslessly through the archival encode/decode" {
    const allocator = std.testing.allocator;
    // Content spanning the full 16-bit range (a gradient across all three
    // components plus a spatial pattern) so the 5/3 DWT and T1 carry high
    // bitplanes and the QCD guard/exponent for 16-bit depth is exercised.
    // The equivalent 80x64 16-bit TIFF was confirmed to decode losslessly
    // through OpenJPEG 2.5.4 and Grok 20.3.6 (jpylyzer-valid) out-of-process.
    const width = 80;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |y| {
        for (0..width) |x| {
            const i = (y * width + x) * 3;
            const r: u32 = @intCast((x * 65535) / @max(width - 1, 1));
            const g: u32 = @intCast(((y * 40000) / @max(height - 1, 1)) ^ ((x * 97 + y * 131) & 0x3ff));
            samples[i + 0] = @intCast(r & 0xffff);
            samples[i + 1] = @intCast(g & 0xffff);
            samples[i + 2] = @intCast((65535 - r) & 0xffff);
        }
    }
    const rgb = image.RgbImage{ .allocator = allocator, .width = width, .height = height, .bit_depth = 16, .samples = samples };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 4,
        .sop = true,
        .eph = true,
        .tlm = true,
    });
    defer allocator.free(bytes);

    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqual(@as(u8, 16), decoded.bit_depth);
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    // The JP2 wrapper carries the 16-bit depth (ihdr bit-depth = 15).
    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
    defer allocator.free(wrapped);
    const info = try jp2.parseInfo(wrapped);
    try std.testing.expectEqual(@as(u8, 16), info.bits_per_component);
}

fn fnv1a64DecodedSamples(samples: []const u16) u64 {
    var h: u64 = 0xcbf29ce484222325;
    for (samples) |sample| {
        inline for (.{ sample & 0xff, (sample >> 8) & 0xff }) |byte| {
            h = (h ^ @as(u64, byte)) *% 0x100000001b3;
        }
    }
    return h;
}

fn foreign97FixtureGradientSample(index: usize) u16 {
    const pixel = index / 3;
    const x: u16 = @intCast(pixel % 32);
    const y: u16 = @intCast(pixel / 32);
    return switch (index % 3) {
        0 => (x * 7 + y * 3) & 0xff,
        1 => (x * 5 + y * 11 + 17) & 0xff,
        else => (x * 13 + y * 2 + 29) & 0xff,
    };
}

fn squaredErrorAgainstForeign97FixtureGradient(samples: []const u16) u64 {
    var sse: u64 = 0;
    for (samples, 0..) |sample, index| {
        const decoded = @as(i32, @intCast(sample));
        const expected = @as(i32, @intCast(foreign97FixtureGradientSample(index)));
        const delta = decoded - expected;
        sse += @as(u64, @intCast(delta * delta));
    }
    return sse;
}

