fn kduMultiPartFixtureGradientSample(index: usize) u16 {
    const pixel = index / 3;
    const x: u16 = @intCast(pixel % 64);
    const y: u16 = @intCast(pixel / 64);
    return switch (index % 3) {
        0 => (x * 7 + y * 3) & 0xff,
        1 => (x * 5 + y * 11 + 17) & 0xff,
        else => (x * 13 + y * 2 + 29) & 0xff,
    };
}

/// Kakadu 8.4.1, 64x64 RGB gradient, `Creversible=yes Stiles={32,32}
/// Clevels=2 Cprecincts={16,16} Cblk={8,8} Clayers=3 Corder=LRCP
/// ORGtparts=L ORGgen_plt=yes`: four 32x32 tiles, three tile-parts per tile
