test "decodes foreign Kakadu multi-part multi-tile JP2s losslessly" {
    const allocator = std.testing.allocator;
    const fixtures = [_]struct { label: []const u8, jp2: []const u8 }{
        .{ .label = "interleaved TNsot-0 layer parts", .jp2 = &kdu_multipart_interleaved_jp2 },
        .{ .label = "TNsot-8 empty padding parts + TLM", .jp2 = &kdu_multipart_padded_jp2 },
    };
    for (fixtures) |fixture| {
        errdefer std.debug.print("kdu multi-part fixture failed: {s}\n", .{fixture.label});
        const cs = try jp2.extractCodestream(fixture.jp2);
        var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, cs, .{ .t1_backend = .iso_mq });
        defer decoded.deinit();
        try std.testing.expectEqual(@as(usize, 64), decoded.width);
        try std.testing.expectEqual(@as(usize, 64), decoded.height);
        try std.testing.expectEqual(@as(usize, 64 * 64 * 3), decoded.samples.len);
        // Reversible 5/3, so the decode must reproduce the source exactly.
        for (decoded.samples, 0..) |sample, index| {
            try std.testing.expectEqual(kduMultiPartFixtureGradientSample(index), sample);
        }
        var threaded = try codestream.decodeLosslessTemporaryWithOptions(allocator, cs, .{ .t1_backend = .iso_mq, .threads = 4 });
        defer threaded.deinit();
        try std.testing.expectEqualSlices(u16, decoded.samples, threaded.samples);
    }
}

test "foreign multi-part tile sequences fail closed on inconsistent accounting" {
    const allocator = std.testing.allocator;
    const cs_view = try jp2.extractCodestream(&kdu_multipart_interleaved_jp2);

    // Walk the tile-part sequence of a codestream copy and return the offset
    // of the n-th SOT (0-based), using Psot to skip packet payload safely.
    const findSot = struct {
        fn find(bytes: []const u8, n: usize) !usize {
            var cursor: usize = 2;
            while (readU16BeTest(bytes, cursor) != codestream.markerValue("sot")) {
                cursor += 2 + readU16BeTest(bytes, cursor + 2);
            }
            var index: usize = 0;
            while (cursor < bytes.len) {
                if (readU16BeTest(bytes, cursor) != codestream.markerValue("sot")) return error.MissingSot;
                if (index == n) return cursor;
                const psot = readU32BeTest(bytes, cursor + 6);
                cursor += psot;
                index += 1;
            }
            return error.MissingSot;
        }
    }.find;

    // (a) Stripping the PLT from a non-empty part leaves a non-empty
    // PLT-less multi-part tile, which has no packet-span source and must
    // fail closed as unsupported.
    {
        const base = try allocator.dupe(u8, cs_view);
        defer allocator.free(base);
        const sot = try findSot(base, 0);
        // First marker segment after the 12-byte SOT header must be the PLT.
        const plt = sot + 12;
        try std.testing.expectEqual(codestream.markerValue("plt"), readU16BeTest(base, plt));
        const plt_total = 2 + @as(usize, readU16BeTest(base, plt + 2));
        var mutated: std.ArrayList(u8) = .empty;
        defer mutated.deinit(allocator);
        try mutated.appendSlice(allocator, base[0..plt]);
        try mutated.appendSlice(allocator, base[plt + plt_total ..]);
        const psot = readU32BeTest(mutated.items, sot + 6);
        writeU32BeTest(mutated.items, sot + 6, @intCast(psot - plt_total));
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.decodeLosslessTemporary(allocator, mutated.items),
        );
    }

    // (b) A signalled part count at or below the current part index is
    // invalid (TNsot 3 -> 2 on a TPsot 2 part).
    {
        const mutated = try allocator.dupe(u8, cs_view);
        defer allocator.free(mutated);
        const sot = try findSot(mutated, 8); // first final part (TPsot 2)
        try std.testing.expectEqual(@as(u8, 2), mutated[sot + 10]);
        try std.testing.expectEqual(@as(u8, 3), mutated[sot + 11]);
        mutated[sot + 11] = 2;
        try std.testing.expectError(
            codestream.CodestreamError.InvalidCodestream,
            codestream.decodeLosslessTemporary(allocator, mutated),
        );
    }

    // (c) A signalled count the stream never satisfies leaves the tile
    // incomplete at EOC.
    {
        const mutated = try allocator.dupe(u8, cs_view);
        defer allocator.free(mutated);
        const sot = try findSot(mutated, 8);
        mutated[sot + 11] = 4;
        try std.testing.expectError(
            codestream.CodestreamError.InvalidCodestream,
            codestream.decodeLosslessTemporary(allocator, mutated),
        );
    }
}

const Foreign97MatrixCase = struct {
    label: []const u8,
    jp2: []const u8,
    reference: []const u8,
};

