        .{ .context = 0, .bit = false },
        .{ .context = 1, .bit = true },
        .{ .context = 0, .bit = false },
        .{ .context = 1, .bit = true },
        .{ .context = 2, .bit = true },
        .{ .context = 2, .bit = false },
        .{ .context = 0, .bit = true },
    };

    var encoded = try mq.encode(allocator, 3, symbols[0..]);
    defer encoded.deinit(allocator);
