test "EBCOT sign coding separates horizontal vertical and mixed sign contexts" {
    const allocator = std.testing.allocator;

    const vertical_plane = [_]i32{ -4, -4 };
    var vertical = try ebcot.encodeBlock(allocator, vertical_plane[0..], 1, .{ .x = 0, .y = 0, .width = 1, .height = 2 });
    defer vertical.deinit(allocator);

    const vertical_top = vertical.symbols[vertical.passes[0].first_symbol..][0..vertical.passes[0].symbol_count];
    try std.testing.expectEqual(@as(usize, 4), vertical_top.len);
    try std.testing.expectEqual(ebcot.SymbolKind.sign, vertical_top[3].kind);
    try std.testing.expectEqual(ebcot.Context.sign1, vertical_top[3].context);
    try std.testing.expectEqual(false, vertical_top[3].bit);

    const opposing_plane = [_]i32{
        -4, 4,
        -4, 4,
    };
    var opposing = try ebcot.encodeBlock(allocator, opposing_plane[0..], 2, .{ .x = 0, .y = 0, .width = 2, .height = 2 });
    defer opposing.deinit(allocator);

    const opposing_top = opposing.symbols[opposing.passes[0].first_symbol..][0..opposing.passes[0].symbol_count];
    try std.testing.expectEqual(@as(usize, 8), opposing_top.len);
    try std.testing.expectEqual(ebcot.SymbolKind.sign, opposing_top[7].kind);
    try std.testing.expectEqual(ebcot.Context.sign2, opposing_top[7].context);
    try std.testing.expectEqual(true, opposing_top[7].bit);

    const matching_plane = [_]i32{
        -4, -4,
        -4, -4,
    };
    var matching = try ebcot.encodeBlock(allocator, matching_plane[0..], 2, .{ .x = 0, .y = 0, .width = 2, .height = 2 });
    defer matching.deinit(allocator);

    const matching_top = matching.symbols[matching.passes[0].first_symbol..][0..matching.passes[0].symbol_count];
    try std.testing.expectEqual(@as(usize, 8), matching_top.len);
    try std.testing.expectEqual(ebcot.SymbolKind.sign, matching_top[7].kind);
    try std.testing.expectEqual(ebcot.Context.sign4, matching_top[7].context);
    try std.testing.expectEqual(false, matching_top[7].bit);
}

test "EBCOT significance propagation precedes cleanup on lower bitplanes" {
    const allocator = std.testing.allocator;
    const plane = [_]i32{ 4, 2 };

    var encoded = try ebcot.encodeBlock(allocator, plane[0..], 2, .{ .x = 0, .y = 0, .width = 2, .height = 1 });
    defer encoded.deinit(allocator);

    try std.testing.expectEqual(ebcot.PassKind.cleanup, encoded.passes[0].kind);
    try std.testing.expectEqual(ebcot.PassKind.significance, encoded.passes[1].kind);
    try std.testing.expectEqual(ebcot.PassKind.refinement, encoded.passes[2].kind);
    try std.testing.expectEqual(ebcot.PassKind.cleanup, encoded.passes[3].kind);

    const sig = encoded.symbols[encoded.passes[1].first_symbol..][0..encoded.passes[1].symbol_count];
    try std.testing.expectEqual(@as(usize, 2), sig.len);
    try std.testing.expectEqual(ebcot.SymbolKind.zero_coding, sig[0].kind);
    try std.testing.expectEqual(true, sig[0].bit);
    try std.testing.expectEqual(@as(usize, 1), sig[0].x);
    try std.testing.expectEqual(ebcot.Context.zero5, sig[0].context);
    try std.testing.expectEqual(ebcot.SymbolKind.sign, sig[1].kind);
    try std.testing.expectEqual(false, sig[1].bit);

    const refinement = encoded.symbols[encoded.passes[2].first_symbol..][0..encoded.passes[2].symbol_count];
    try std.testing.expectEqual(@as(usize, 1), refinement.len);
    try std.testing.expectEqual(ebcot.SymbolKind.magnitude_refinement, refinement[0].kind);
    try std.testing.expectEqual(@as(usize, 0), refinement[0].x);
    try std.testing.expectEqual(false, refinement[0].bit);
}

test "EBCOT zero coding context follows subband orientation" {
    const allocator = std.testing.allocator;
    const plane = [_]i32{ 4, 2 };
    const rect = subband.Rect{ .x = 0, .y = 0, .width = 2, .height = 1 };

    var ll = try ebcot.encodeBlockWithStyle(allocator, plane[0..], 2, rect, .{ .band_kind = .ll });
    defer ll.deinit(allocator);
    var hl = try ebcot.encodeBlockWithStyle(allocator, plane[0..], 2, rect, .{ .band_kind = .hl });
    defer hl.deinit(allocator);
    var hh = try ebcot.encodeBlockWithStyle(allocator, plane[0..], 2, rect, .{ .band_kind = .hh });
    defer hh.deinit(allocator);

    const ll_sig = ll.symbols[ll.passes[1].first_symbol..][0..ll.passes[1].symbol_count];
    const hl_sig = hl.symbols[hl.passes[1].first_symbol..][0..hl.passes[1].symbol_count];
    const hh_sig = hh.symbols[hh.passes[1].first_symbol..][0..hh.passes[1].symbol_count];

    // ISO Table D.1: HL swaps H/V neighbor roles; LL and LH share the plain
    // table.
    try std.testing.expectEqual(ebcot.Context.zero5, ll_sig[0].context);
    try std.testing.expectEqual(ebcot.Context.zero3, hl_sig[0].context);
    try std.testing.expectEqual(ebcot.Context.zero1, hh_sig[0].context);
}

test "EBCOT refinement context tracks first and later refinements" {
    const allocator = std.testing.allocator;
    const plane = [_]i32{
        8, 0, 0, 8, 8,
    };

    var encoded = try ebcot.encodeBlock(allocator, plane[0..], 5, .{ .x = 0, .y = 0, .width = 5, .height = 1 });
    defer encoded.deinit(allocator);

    const first_refinement = encoded.symbols[encoded.passes[2].first_symbol..][0..encoded.passes[2].symbol_count];
    try std.testing.expectEqual(@as(usize, 3), first_refinement.len);
    try std.testing.expectEqual(ebcot.Context.refinement, first_refinement[0].context);
    try std.testing.expectEqual(@as(usize, 0), first_refinement[0].x);
    try std.testing.expectEqual(ebcot.Context.refinement_neighbor, first_refinement[1].context);
    try std.testing.expectEqual(@as(usize, 3), first_refinement[1].x);
    try std.testing.expectEqual(ebcot.Context.refinement_neighbor, first_refinement[2].context);
    try std.testing.expectEqual(@as(usize, 4), first_refinement[2].x);

    const second_refinement = encoded.symbols[encoded.passes[5].first_symbol..][0..encoded.passes[5].symbol_count];
    try std.testing.expectEqual(@as(usize, 3), second_refinement.len);
    try std.testing.expectEqual(ebcot.Context.refinement_later, second_refinement[0].context);
    try std.testing.expectEqual(ebcot.Context.refinement_later, second_refinement[1].context);
    try std.testing.expectEqual(ebcot.Context.refinement_later, second_refinement[2].context);
}

