    const rect = subband.Rect{ .x = 0, .y = 0, .width = width, .height = height };

    {
        var block = try ebcot.encodeBlock(allocator, plane[0..], width, rect);
        defer block.deinit(allocator);
        var full = try ebcot.encodeBlockSymbolsSegmentContinuous(allocator, .{
            .bitplanes = block.bitplanes,
            .non_zero_count = block.non_zero_count,
            .passes = block.passes,
            .symbols = block.symbols,
        });
        defer full.deinit(allocator);
        try std.testing.expect(full.pass_count >= 3);

        const pass_count: u16 = 2;
        const byte_length = full.passes[pass_count - 1].cumulative_bytes;
        const decoded = try ebcot.decodeCodeBlockPayloadContinuousInferred(
            allocator,
            full.bitplanes,
            pass_count,
            full.bytes[0..@intCast(byte_length)],
            width,
            height,
        );
        defer allocator.free(decoded);
        try std.testing.expectEqual(@as(usize, width * height), decoded.len);
        try std.testing.expect(countNonZeroI32Test(decoded) <= full.non_zero_count);
    }

    {
        var direct_scratch = ebcot.DirectBlockScratch.init(allocator);
        defer direct_scratch.deinit();
        var full = try ebcot.encodeCodeBlockSegmentDirectIsoScratchWithStyle(&direct_scratch, plane[0..], width, rect, .{});
        defer full.deinit(allocator);
        try std.testing.expect(full.pass_count >= 3);

        const pass_count: u16 = 2;
        const byte_length = full.passes[pass_count - 1].cumulative_bytes;
        const decoded = try ebcot.decodeCodeBlockPayloadContinuousInferredIsoMqWithStyle(
            allocator,
            full.bitplanes,
            pass_count,
            full.bytes[0..@intCast(byte_length)],
            width,
            height,
            .{},
        );
        defer allocator.free(decoded);
        try std.testing.expectEqual(@as(usize, width * height), decoded.len);
        try std.testing.expect(countNonZeroI32Test(decoded) <= full.non_zero_count);
    }
}

