test "EBCOT terminate-all style writes and decodes pass-terminated MQ segments" {
    const allocator = std.testing.allocator;
    const width = 4;
    const height = 5;
    const plane = [_]i32{
        4,  0,  -5, 2,
        0,  8,  0,  -3,
        7,  0,  1,  0,
        -6, 2,  0,  5,
        0,  -9, 3,  10,
    };
    const rect = subband.Rect{ .x = 0, .y = 0, .width = width, .height = height };
    const style = ebcot.CodeBlockStyle{
        .terminate_all = true,
        .vertical_causal = true,
        .segmentation_symbols = true,
    };

    var terminated = try ebcot.encodeCodeBlockSegmentContinuousWithStyle(allocator, plane[0..], width, rect, style);
    defer terminated.deinit(allocator);
    try expectMarkerStuffingIsValid(terminated.bytes);

    const decoded = try ebcot.decodeCodeBlockSegmentCoefficientsContinuousWithStyle(allocator, terminated, width, height, style);
    defer allocator.free(decoded);
    try std.testing.expectEqualSlices(i32, plane[0..], decoded);

    const reset_style = ebcot.CodeBlockStyle{
        .reset_context = true,
        .terminate_all = true,
        .vertical_causal = true,
        .segmentation_symbols = true,
    };
    var reset_block = try ebcot.encodeBlockWithStyle(allocator, plane[0..], width, rect, reset_style);
    defer reset_block.deinit(allocator);
    var reset_oracle = try ebcot.encodeBlockSymbolsSegment(allocator, .{
        .bitplanes = reset_block.bitplanes,
        .non_zero_count = reset_block.non_zero_count,
        .passes = reset_block.passes,
        .symbols = reset_block.symbols,
    });
    defer reset_oracle.deinit(allocator);
    var terminated_reset = try ebcot.encodeCodeBlockSegmentContinuousWithStyle(allocator, plane[0..], width, rect, reset_style);
    defer terminated_reset.deinit(allocator);
    try expectMarkerStuffingIsValid(terminated_reset.bytes);

    try std.testing.expectEqualSlices(ebcot.CodeBlockPassPayload, reset_oracle.passes, terminated_reset.passes);
    try std.testing.expectEqualSlices(u8, reset_oracle.bytes, terminated_reset.bytes);
    try std.testing.expect(!std.mem.eql(u8, reset_oracle.bytes, terminated.bytes));

    try std.testing.expectError(
        ebcot.EbcotError.InvalidBlock,
        ebcot.decodeCodeBlockPayloadContinuousInferredWithStyle(allocator, terminated.bitplanes, terminated.pass_count, terminated.bytes, width, height, style),
    );
}

test "EBCOT ISO MQ predictable termination decodes larger terminated block" {
    const allocator = std.testing.allocator;
    const stride = 257;
    const image_height = 383;
    const width = 64;
    const height = 64;
    var plane: [stride * image_height]i32 = undefined;
    for (&plane, 0..) |*sample, i| {
        const base: i32 = @intCast((i * 37 + i / 11 * 53) % 511);
        sample.* = if ((i & 3) == 0) -base else base;
    }
    const rect = subband.Rect{ .x = 129, .y = 71, .width = width, .height = height };
    inline for (.{ subband.Kind.ll, subband.Kind.hl, subband.Kind.lh, subband.Kind.hh }) |kind| {
        const style = ebcot.CodeBlockStyle{
            .band_kind = kind,
            .terminate_all = true,
            .predictable_termination = true,
        };

        var segment = try ebcot.encodeCodeBlockSegmentIsoMqTerminatedWithStyle(allocator, plane[0..], stride, rect, style);
        defer segment.deinit(allocator);
        const segments = segment.segments orelse return error.MissingSegments;
        const segment_lengths = try allocator.alloc(u64, segments.len);
        defer allocator.free(segment_lengths);
        for (segments, segment_lengths) |span, *length| length.* = span.byte_length;

        var scratch = ebcot.DecodeBlockScratch.init(allocator);
        defer scratch.deinit();
        const decoded = try ebcot.decodeCodeBlockPayloadTerminatedIsoMqScratchWithStyleProfiledBorrowed(
            &scratch,
            segment.bitplanes,
            segment.pass_count,
            segment.bytes,
            segment_lengths,
            width,
            height,
            style,
            null,
        );
        for (0..height) |y| {
            const src = plane[(rect.y + y) * stride + rect.x ..][0..width];
            const dst = decoded[y * width ..][0..width];
            try std.testing.expectEqualSlices(i32, src, dst);
        }
    }
}

