    try std.testing.expectEqual(@as(usize, 0), segment.bytes.len);
    try std.testing.expectEqual(ebcot.TruncationPoint{ .cumulative_passes = 0, .cumulative_bytes = 0 }, try segment.truncationPointForPasses(0));
}

