        samples[i * 3 + 0] = @as(u16, @intCast((seed >> 16) & 0xff));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 13 + 17) & 0xff));
        samples[i * 3 + 2] = @as(u16, @intCast(((i / width) * 19 + i) & 0xff));
    }

    const rgb = image.RgbImage{
