test "irreversible 9/7 ICT codestream roundtrips within lossy tolerance" {
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |row| {
        for (0..width) |col| {
            const i = row * width + col;
            samples[i * 3 + 0] = @intCast((col * 4) % 256);
            samples[i * 3 + 1] = @intCast((row * 4) % 256);
            samples[i * 3 + 2] = @intCast((col * 2 + row * 2) % 256);
        }
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
    });
    defer allocator.free(bytes);

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{});
    defer decoded.deinit();
    try std.testing.expectEqual(rgb.width, decoded.width);
    try std.testing.expectEqual(rgb.height, decoded.height);

    var max_diff: i32 = 0;
    var sum_sq: u64 = 0;
    for (samples, decoded.samples) |expected, actual| {
        const diff = @as(i32, expected) - @as(i32, actual);
        max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
        sum_sq += @as(u64, @intCast(diff * diff));
    }
    // Default step sizes follow the OpenJPEG explicit table, so the smooth
    // gradient should reconstruct within a few code values.
    try std.testing.expect(max_diff <= 8);
    const mse = @as(f64, @floatFromInt(sum_sq)) / @as(f64, @floatFromInt(samples.len));
    try std.testing.expect(mse < 4.0);
}

test "scalar-derived quantization signals one QCD step and roundtrips within lossy tolerance" {
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |row| {
        for (0..width) |col| {
            const i = row * width + col;
            samples[i * 3 + 0] = @intCast((col * 4) % 256);
            samples[i * 3 + 1] = @intCast((row * 4) % 256);
            samples[i * 3 + 2] = @intCast((col * 2 + row * 2) % 256);
        }
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const derived = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_derived,
    });
    defer allocator.free(derived);
    const expounded = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
    });
    defer allocator.free(expounded);

    // QCD carries a single (epsilon, mu) pair for scalar-derived: Lqcd is
    // 3 (length + style) + 2 bytes, and the style byte advertises guard
    // bits 2 with quantization style 1.
    const derived_qcd = findMarker(derived, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    try std.testing.expectEqual(@as(u8, 0), derived[derived_qcd + 2]);
    try std.testing.expectEqual(@as(u8, 5), derived[derived_qcd + 3]);
    try std.testing.expectEqual(@as(u8, (2 << 5) | 1), derived[derived_qcd + 4]);
    const expounded_qcd = findMarker(expounded, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    try std.testing.expectEqual(@as(u8, (2 << 5) | 2), expounded[expounded_qcd + 4]);

    // Derived step sizes differ from the expounded table, so the coded
    // payload differs.
    try std.testing.expect(!std.mem.eql(u8, derived, expounded));

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, derived, .{});
    defer decoded.deinit();
    try std.testing.expectEqual(rgb.width, decoded.width);
    try std.testing.expectEqual(rgb.height, decoded.height);

    var max_diff: i32 = 0;
    var sum_sq: u64 = 0;
    for (samples, decoded.samples) |expected, actual| {
        const diff = @as(i32, expected) - @as(i32, actual);
        max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
        sum_sq += @as(u64, @intCast(diff * diff));
    }
    // Derived steps grow coarser toward finer resolutions than the expounded
    // norm-based table, so allow a wider (but still tight) tolerance.
    try std.testing.expect(max_diff <= 16);
    const mse = @as(f64, @floatFromInt(sum_sq)) / @as(f64, @floatFromInt(samples.len));
    try std.testing.expect(mse < 16.0);

    const rewritten = try allocator.dupe(u8, derived);
    defer allocator.free(rewritten);
    const rewritten_qcd = findMarker(rewritten, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const value = readU16BeTest(rewritten, rewritten_qcd + 5);
    writeU16BeTest(rewritten, rewritten_qcd + 5, (value & 0xf800) | 0x07ff);
    var decoded_rewritten = try codestream.decodeLosslessTemporaryWithOptions(allocator, rewritten, .{});
    defer decoded_rewritten.deinit();
    try std.testing.expectEqual(rgb.width, decoded_rewritten.width);
    try std.testing.expectEqual(rgb.height, decoded_rewritten.height);
    try std.testing.expectEqual(rgb.bit_depth, decoded_rewritten.bit_depth);

    var changed_samples: usize = 0;
    for (decoded.samples, decoded_rewritten.samples) |base, actual| {
        if (base != actual) changed_samples += 1;
    }
    try std.testing.expect(changed_samples > 0);

    const derived_guard_one = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_derived,
        .guard_bits = 1,
    });
    defer allocator.free(derived_guard_one);
    const derived_guard_one_qcd = findMarker(derived_guard_one, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    try std.testing.expectEqual(@as(u8, (1 << 5) | 1), derived_guard_one[derived_guard_one_qcd + 4]);
    var decoded_guard_one = try codestream.decodeLosslessTemporaryWithOptions(allocator, derived_guard_one, .{});
    defer decoded_guard_one.deinit();
    try std.testing.expectEqual(rgb.width, decoded_guard_one.width);
    try std.testing.expectEqual(rgb.height, decoded_guard_one.height);
    try std.testing.expectEqual(rgb.bit_depth, decoded_guard_one.bit_depth);
}

test "irreversible QCD scalar-expounded decode follows signalled mantissas" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |row| {
        for (0..width) |col| {
            const i = row * width + col;
            samples[i * 3 + 0] = @intCast((col * 5 + row * 3) % 256);
            samples[i * 3 + 1] = @intCast((col * 2 + row * 7 + 19) % 256);
            samples[i * 3 + 2] = @intCast((col * 9 + row + 31) % 256);
        }
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
        .emit_temporary_payload_sidecar = false,
    });
    defer allocator.free(bytes);

    var baseline = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{});
    defer baseline.deinit();

    const rewritten = try allocator.dupe(u8, bytes);
    defer allocator.free(rewritten);
    const qcd = findMarker(rewritten, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const lqcd = readU16BeTest(rewritten, qcd + 2);
    try std.testing.expectEqual(@as(u8, (2 << 5) | 2), rewritten[qcd + 4]);
    const step_count = (@as(usize, lqcd) - 3) / 2;
    var step_index: usize = 0;
    while (step_index < step_count) : (step_index += 1) {
        const offset = qcd + 5 + step_index * 2;
        const value = readU16BeTest(rewritten, offset);
        const exponent = value & 0xf800;
        writeU16BeTest(rewritten, offset, exponent | 0x07ff);
    }

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, rewritten, .{});
    defer decoded.deinit();
    try std.testing.expectEqual(rgb.width, decoded.width);
    try std.testing.expectEqual(rgb.height, decoded.height);
    try std.testing.expectEqual(rgb.bit_depth, decoded.bit_depth);

    var changed_samples: usize = 0;
    for (baseline.samples, decoded.samples) |base, actual| {
        if (base != actual) changed_samples += 1;
    }
    try std.testing.expect(changed_samples > 0);

    const guard_one = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
        .guard_bits = 1,
        .emit_temporary_payload_sidecar = false,
    });
    defer allocator.free(guard_one);
    const guard_one_qcd = findMarker(guard_one, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    try std.testing.expectEqual(@as(u8, (1 << 5) | 2), guard_one[guard_one_qcd + 4]);
    var decoded_guard_one = try codestream.decodeLosslessTemporaryWithOptions(allocator, guard_one, .{});
    defer decoded_guard_one.deinit();
    try std.testing.expectEqual(rgb.width, decoded_guard_one.width);
    try std.testing.expectEqual(rgb.height, decoded_guard_one.height);
    try std.testing.expectEqual(rgb.bit_depth, decoded_guard_one.bit_depth);
}

