test "direct ISO segment encoder matches the symbol-based encoder byte for byte" {
    const allocator = std.testing.allocator;
    const w = 32;
    const h = 32;
    var plane: [w * h]i32 = undefined;

    var scratch = ebcot.DirectBlockScratch.init(allocator);
    defer scratch.deinit();

    var seed: u32 = 77;
    const kinds = [_]subband.Kind{ .ll, .hl, .lh, .hh };
    const StyleMode = struct { bypass: bool, reset: bool, erterm: bool = false };
    const style_modes = [_]StyleMode{
        .{ .bypass = false, .reset = false },
        .{ .bypass = true, .reset = false },
        .{ .bypass = false, .reset = true },
        .{ .bypass = false, .reset = false, .erterm = true },
        .{ .bypass = false, .reset = true, .erterm = true },
        .{ .bypass = true, .reset = true },
        .{ .bypass = true, .reset = false, .erterm = true },
        .{ .bypass = true, .reset = true, .erterm = true },
    };
    for (kinds) |kind| {
        for (style_modes) |mode| {
            const bypass = mode.bypass;
            for (&plane) |*value| {
                seed = seed *% 1664525 +% 1013904223;
                const magnitude: i32 = @intCast((seed >> 7) & 0x3ff);
                value.* = if ((seed & 1) == 1) -magnitude else magnitude;
            }
            const style = ebcot.CodeBlockStyle{
                .band_kind = kind,
                .bypass = bypass,
                .reset_context = mode.reset,
                .predictable_termination = mode.erterm,
            };
            const rect = subband.Rect{ .x = 0, .y = 0, .width = w, .height = h };

            var block = try ebcot.encodeBlockWithStyle(allocator, &plane, w, rect, style);
            defer block.deinit(allocator);
            const view = ebcot.EncodedBlockView{
                .bitplanes = block.bitplanes,
                .non_zero_count = block.non_zero_count,
                .passes = block.passes,
                .symbols = block.symbols,
            };
            var expected = if (bypass)
                try ebcot.encodeBlockSymbolsSegmentIsoMqBypass(allocator, view, style)
            else
                try ebcot.encodeBlockSymbolsSegmentIsoMqContinuousWithStyle(allocator, view, style);
            defer expected.deinit(allocator);

            var actual = try ebcot.encodeCodeBlockSegmentDirectIsoScratchWithStyle(&scratch, &plane, w, rect, style);
            defer actual.deinit(allocator);

            try std.testing.expectEqual(expected.bitplanes, actual.bitplanes);
            try std.testing.expectEqual(expected.pass_count, actual.pass_count);
            try std.testing.expectEqualSlices(u8, expected.bytes, actual.bytes);
            if (bypass) {
                const expected_segments = expected.segments orelse return error.TestUnexpectedResult;
                const actual_segments = actual.segments orelse return error.TestUnexpectedResult;
                try std.testing.expectEqualSlices(ebcot.SegmentSpan, expected_segments, actual_segments);
            } else {
                try std.testing.expectEqual(@as(?[]ebcot.SegmentSpan, null), actual.segments);
            }
        }
    }
}

test "strict decode rejects COD whose blocks cross precinct spans" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    // Valid geometry: 32x32 blocks inside 64x64 precincts (band span 32).
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .block_width = 32,
        .block_height = 32,
        .precincts = [_]codestream.PrecinctSize{.{ .width = 64, .height = 64 }} ** 33,
        .precinct_count = 1,
    });
    defer allocator.free(bytes);

    // Shrink the signalled precincts to 32x32 (exponent byte 0x55): the band
    // span above resolution 0 drops to 16 < the 32-sample block, which would
    // require B.7 block clamping; the strict reader must fail closed.
    const corrupted = try allocator.dupe(u8, bytes);
    defer allocator.free(corrupted);
    const cod = findMarker(corrupted, codestream.markerValue("cod")) orelse return error.MissingCod;
    const levels = corrupted[cod + 9];
    for (0..@as(usize, levels) + 1) |index| {
        corrupted[cod + 14 + index] = 0x55;
    }
    try std.testing.expectError(
        codestream.CodestreamError.UnsupportedPayload,
        codestream.decodeLosslessTemporary(allocator, corrupted),
    );
}

test "redundant COC/QCC that byte-replicate the main COD/QCD decode byte-exactly" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{ .allocator = allocator, .width = width, .height = height, .bit_depth = 8, .samples = samples };

    const base = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2 });
    defer allocator.free(base);

    // Build a COC for component 1 that replicates the main COD: Ccoc(1) +
    // Scoc(1, = COD Scod & 0x01) + SPcoc(= COD coding fields, COD segment[5..]).
    const cod = findMarker(base, codestream.markerValue("cod")) orelse return error.MissingCod;
    const cod_len = (@as(usize, base[cod + 2]) << 8) | base[cod + 3];
    const cod_seg = base[cod + 4 ..][0 .. cod_len - 2]; // COD payload (Scod..precincts)
    const cod_scod = cod_seg[0];
    const cod_coding = cod_seg[5..]; // NL,xcb,ycb,cblk,transform,precincts

    var coc_payload: std.ArrayList(u8) = .empty;
    defer coc_payload.deinit(allocator);
    try coc_payload.append(allocator, 1); // Ccoc: component 1
    try coc_payload.append(allocator, cod_scod & 0x01); // Scoc precinct flag
    try coc_payload.appendSlice(allocator, cod_coding);

    // Build a QCC for component 2 that replicates the main QCD: Cqcc(1) +
    // (Sqcd + steps = the whole QCD payload).
    const qcd = findMarker(base, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const qcd_len = (@as(usize, base[qcd + 2]) << 8) | base[qcd + 3];
    const qcd_seg = base[qcd + 4 ..][0 .. qcd_len - 2];
    var qcc_payload: std.ArrayList(u8) = .empty;
    defer qcc_payload.deinit(allocator);
    try qcc_payload.append(allocator, 2); // Cqcc: component 2
    try qcc_payload.appendSlice(allocator, qcd_seg);

    // Splice COC after COD and QCC after QCD (both after their main markers).
    const spliceMarker = struct {
        fn run(a: std.mem.Allocator, stream: []const u8, after_marker: usize, after_len: usize, marker: u16, mpayload: []const u8) ![]u8 {
            const insert_at = after_marker + 4 + (after_len - 2);
            var out: std.ArrayList(u8) = .empty;
            errdefer out.deinit(a);
            try out.appendSlice(a, stream[0..insert_at]);
            try out.append(a, @intCast(marker >> 8));
            try out.append(a, @intCast(marker & 0xff));
            const seg_len: u16 = @intCast(mpayload.len + 2);
            try out.append(a, @intCast(seg_len >> 8));
            try out.append(a, @intCast(seg_len & 0xff));
            try out.appendSlice(a, mpayload);
            try out.appendSlice(a, stream[insert_at..]);
            return out.toOwnedSlice(a);
        }
    }.run;

    const with_coc = try spliceMarker(allocator, base, cod, cod_len, codestream.markerValue("coc"), coc_payload.items);
    defer allocator.free(with_coc);
    // Re-find QCD in the extended stream (shifted by the COC bytes).
    const qcd2 = findMarker(with_coc, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const qcd2_len = (@as(usize, with_coc[qcd2 + 2]) << 8) | with_coc[qcd2 + 3];
    const spliced = try spliceMarker(allocator, with_coc, qcd2, qcd2_len, codestream.markerValue("qcc"), qcc_payload.items);
    defer allocator.free(spliced);

    // The strict decoder accepts the redundant COC/QCC and reconstructs the
    // exact same image.
    var decoded = try codestream.decodeLosslessTemporary(allocator, spliced);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    // The JP2 wrapper accepts the COC/QCC-carrying codestream.
    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, spliced);
    defer allocator.free(wrapped);
    _ = try jp2.parseInfo(wrapped);

    // A COC whose coding fields differ from the main COD (flip the transform
    // byte) is a genuine per-component override and must fail closed.
    const bad = try allocator.dupe(u8, spliced);
    defer allocator.free(bad);
    const bad_coc = findMarker(bad, codestream.markerValue("coc")) orelse return error.MissingCoc;
    // COC payload: [Ccoc][Scoc][NL][xcb][ycb][cblk][transform]... transform is
    // payload index 6 → byte offset bad_coc + 4 + 6.
    bad[bad_coc + 4 + 6] ^= 0x01;
    try std.testing.expectError(codestream.CodestreamError.UnsupportedPayload, codestream.decodeLosslessTemporary(allocator, bad));
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, bad));

    const bad_wrapped_coc = try allocator.dupe(u8, wrapped);
    defer allocator.free(bad_wrapped_coc);
    const bad_wrapped_payload = try findJp2BoxPayload(bad_wrapped_coc, "jp2c");
    bad_wrapped_coc[bad_wrapped_payload.start + bad_coc + 4 + 6] ^= 0x01;
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.parseInfo(bad_wrapped_coc));

    // Reserved Scoc bits are malformed COC syntax, not a supported redundant
    // marker nor a valid per-component override.
    const invalid_coc_scoc_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_coc_scoc_stream);
    const invalid_coc_scoc = findMarker(invalid_coc_scoc_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    invalid_coc_scoc_stream[invalid_coc_scoc + 5] |= 0x80;
    try std.testing.expectError(codestream.CodestreamError.InvalidCodestream, codestream.decodeLosslessTemporary(allocator, invalid_coc_scoc_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_coc_scoc_stream));

    const invalid_coc_scoc_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_coc_scoc_wrapped);
    const invalid_coc_scoc_wrapped_payload = try findJp2BoxPayload(invalid_coc_scoc_wrapped, "jp2c");
    invalid_coc_scoc_wrapped[invalid_coc_scoc_wrapped_payload.start + invalid_coc_scoc + 5] |= 0x80;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_coc_scoc_wrapped));

    const invalid_coc_levels_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_coc_levels_stream);
    const invalid_coc_levels = findMarker(invalid_coc_levels_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    invalid_coc_levels_stream[invalid_coc_levels + 4 + 2] = 33;
    try std.testing.expectError(codestream.CodestreamError.TooManyLevels, codestream.decodeLosslessTemporary(allocator, invalid_coc_levels_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_coc_levels_stream));

    const invalid_coc_levels_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_coc_levels_wrapped);
    const invalid_coc_levels_wrapped_payload = try findJp2BoxPayload(invalid_coc_levels_wrapped, "jp2c");
    invalid_coc_levels_wrapped[invalid_coc_levels_wrapped_payload.start + invalid_coc_levels + 4 + 2] = 33;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_coc_levels_wrapped));

    const invalid_coc_block_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_coc_block_stream);
    const invalid_coc_block = findMarker(invalid_coc_block_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    invalid_coc_block_stream[invalid_coc_block + 4 + 3] = 9;
    try std.testing.expectError(codestream.CodestreamError.InvalidCodestream, codestream.decodeLosslessTemporary(allocator, invalid_coc_block_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_coc_block_stream));

    const invalid_coc_block_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_coc_block_wrapped);
    const invalid_coc_block_wrapped_payload = try findJp2BoxPayload(invalid_coc_block_wrapped, "jp2c");
    invalid_coc_block_wrapped[invalid_coc_block_wrapped_payload.start + invalid_coc_block + 4 + 3] = 9;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_coc_block_wrapped));

    const invalid_coc_style_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_coc_style_stream);
    const invalid_coc_style = findMarker(invalid_coc_style_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    invalid_coc_style_stream[invalid_coc_style + 4 + 5] = 0x40;
    try std.testing.expectError(codestream.CodestreamError.InvalidCodestream, codestream.decodeLosslessTemporary(allocator, invalid_coc_style_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_coc_style_stream));

    const invalid_coc_style_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_coc_style_wrapped);
    const invalid_coc_style_wrapped_payload = try findJp2BoxPayload(invalid_coc_style_wrapped, "jp2c");
    invalid_coc_style_wrapped[invalid_coc_style_wrapped_payload.start + invalid_coc_style + 4 + 5] = 0x40;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_coc_style_wrapped));

    const unsupported_coc_style_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(unsupported_coc_style_stream);
    const unsupported_coc_style = findMarker(unsupported_coc_style_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    unsupported_coc_style_stream[unsupported_coc_style + 4 + 5] = 0x02;
    try std.testing.expectError(codestream.CodestreamError.UnsupportedPayload, codestream.decodeLosslessTemporary(allocator, unsupported_coc_style_stream));
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, unsupported_coc_style_stream));

    const unsupported_coc_style_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(unsupported_coc_style_wrapped);
    const unsupported_coc_style_wrapped_payload = try findJp2BoxPayload(unsupported_coc_style_wrapped, "jp2c");
    unsupported_coc_style_wrapped[unsupported_coc_style_wrapped_payload.start + unsupported_coc_style + 4 + 5] = 0x02;
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.parseInfo(unsupported_coc_style_wrapped));

    const invalid_coc_transform_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_coc_transform_stream);
    const invalid_coc_transform = findMarker(invalid_coc_transform_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    invalid_coc_transform_stream[invalid_coc_transform + 4 + 6] = 2;
    try std.testing.expectError(codestream.CodestreamError.InvalidCodestream, codestream.decodeLosslessTemporary(allocator, invalid_coc_transform_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_coc_transform_stream));

    const invalid_coc_transform_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_coc_transform_wrapped);
    const invalid_coc_transform_wrapped_payload = try findJp2BoxPayload(invalid_coc_transform_wrapped, "jp2c");
    invalid_coc_transform_wrapped[invalid_coc_transform_wrapped_payload.start + invalid_coc_transform + 4 + 6] = 2;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_coc_transform_wrapped));

    const short_coc_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(short_coc_stream);
    const short_coc = findMarker(short_coc_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    writeU16BeTest(short_coc_stream, short_coc + 2, 4);
    try std.testing.expectError(codestream.CodestreamError.TruncatedData, codestream.decodeLosslessTemporary(allocator, short_coc_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, short_coc_stream));

    const short_coc_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(short_coc_wrapped);
    const short_coc_wrapped_payload = try findJp2BoxPayload(short_coc_wrapped, "jp2c");
    writeU16BeTest(short_coc_wrapped, short_coc_wrapped_payload.start + short_coc + 2, 4);
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(short_coc_wrapped));

    // A QCC whose quantization bytes differ from the main QCD is likewise a
    // genuine per-component override.
    const bad_qcc_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(bad_qcc_stream);
    const bad_qcc = findMarker(bad_qcc_stream, codestream.markerValue("qcc")) orelse return error.MissingQcc;
    bad_qcc_stream[bad_qcc + 6] ^= 0x08;
    try std.testing.expectError(codestream.CodestreamError.UnsupportedPayload, codestream.decodeLosslessTemporary(allocator, bad_qcc_stream));
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, bad_qcc_stream));

    const bad_wrapped_qcc = try allocator.dupe(u8, wrapped);
    defer allocator.free(bad_wrapped_qcc);
    const bad_wrapped_qcc_payload = try findJp2BoxPayload(bad_wrapped_qcc, "jp2c");
    bad_wrapped_qcc[bad_wrapped_qcc_payload.start + bad_qcc + 6] ^= 0x08;
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.parseInfo(bad_wrapped_qcc));

    // Structurally invalid QCC bytes are malformed codestream data, not merely
    // unsupported per-component overrides.
    const invalid_qcc_style_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(invalid_qcc_style_stream);
    const invalid_qcc_style = findMarker(invalid_qcc_style_stream, codestream.markerValue("qcc")) orelse return error.MissingQcc;
    invalid_qcc_style_stream[invalid_qcc_style + 5] = 0x5f;
    try std.testing.expectError(codestream.CodestreamError.InvalidCodestream, codestream.decodeLosslessTemporary(allocator, invalid_qcc_style_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, invalid_qcc_style_stream));

    const invalid_qcc_style_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(invalid_qcc_style_wrapped);
    const invalid_qcc_style_wrapped_payload = try findJp2BoxPayload(invalid_qcc_style_wrapped, "jp2c");
    invalid_qcc_style_wrapped[invalid_qcc_style_wrapped_payload.start + invalid_qcc_style + 5] = 0x5f;
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(invalid_qcc_style_wrapped));

    const short_qcc_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(short_qcc_stream);
    const short_qcc = findMarker(short_qcc_stream, codestream.markerValue("qcc")) orelse return error.MissingQcc;
    writeU16BeTest(short_qcc_stream, short_qcc + 2, 4);
    try std.testing.expectError(codestream.CodestreamError.TruncatedData, codestream.decodeLosslessTemporary(allocator, short_qcc_stream));
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.wrapRgbCodestream(allocator, rgb, short_qcc_stream));

    const short_qcc_wrapped = try allocator.dupe(u8, wrapped);
    defer allocator.free(short_qcc_wrapped);
    const short_qcc_wrapped_payload = try findJp2BoxPayload(short_qcc_wrapped, "jp2c");
    writeU16BeTest(short_qcc_wrapped, short_qcc_wrapped_payload.start + short_qcc + 2, 4);
    try std.testing.expectError(jp2.Jp2Error.InvalidCodestream, jp2.parseInfo(short_qcc_wrapped));

    // Component indexes outside the RGB component set are not redundant for
    // this profile even when their payload bytes otherwise match.
    const bad_coc_component_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(bad_coc_component_stream);
    const bad_coc_component = findMarker(bad_coc_component_stream, codestream.markerValue("coc")) orelse return error.MissingCoc;
    bad_coc_component_stream[bad_coc_component + 4] = 3;
    try std.testing.expectError(codestream.CodestreamError.UnsupportedPayload, codestream.decodeLosslessTemporary(allocator, bad_coc_component_stream));
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, bad_coc_component_stream));

    const bad_wrapped_coc_component = try allocator.dupe(u8, wrapped);
    defer allocator.free(bad_wrapped_coc_component);
    const bad_wrapped_coc_component_payload = try findJp2BoxPayload(bad_wrapped_coc_component, "jp2c");
    bad_wrapped_coc_component[bad_wrapped_coc_component_payload.start + bad_coc_component + 4] = 3;
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.parseInfo(bad_wrapped_coc_component));

    const bad_qcc_component_stream = try allocator.dupe(u8, spliced);
    defer allocator.free(bad_qcc_component_stream);
    const bad_qcc_component = findMarker(bad_qcc_component_stream, codestream.markerValue("qcc")) orelse return error.MissingQcc;
    bad_qcc_component_stream[bad_qcc_component + 4] = 3;
    try std.testing.expectError(codestream.CodestreamError.UnsupportedPayload, codestream.decodeLosslessTemporary(allocator, bad_qcc_component_stream));
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, bad_qcc_component_stream));

    const bad_wrapped_qcc_component = try allocator.dupe(u8, wrapped);
    defer allocator.free(bad_wrapped_qcc_component);
    const bad_wrapped_qcc_component_payload = try findJp2BoxPayload(bad_wrapped_qcc_component, "jp2c");
    bad_wrapped_qcc_component[bad_wrapped_qcc_component_payload.start + bad_qcc_component + 4] = 3;
    try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.parseInfo(bad_wrapped_qcc_component));
}

fn spliceMarkerSegmentForTest(
    allocator: std.mem.Allocator,
    stream: []const u8,
    insert_at: usize,
    marker: u16,
    payload: []const u8,
) ![]u8 {
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, stream[0..insert_at]);
    try out.append(allocator, @intCast(marker >> 8));
    try out.append(allocator, @intCast(marker & 0xff));
    const seg_len: u16 = @intCast(payload.len + 2);
    try out.append(allocator, @intCast(seg_len >> 8));
    try out.append(allocator, @intCast(seg_len & 0xff));
    try out.appendSlice(allocator, payload);
    try out.appendSlice(allocator, stream[insert_at..]);
    return out.toOwnedSlice(allocator);
}

fn duplicateMarkerSegmentForTest(allocator: std.mem.Allocator, stream: []const u8, marker: u16) ![]u8 {
    const start = findMarker(stream, marker) orelse return error.MissingMarker;
    const end = try markerSegmentEndForTest(stream, start);
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, stream[0..end]);
    try out.appendSlice(allocator, stream[start..end]);
    try out.appendSlice(allocator, stream[end..]);
    return out.toOwnedSlice(allocator);
}

fn moveMarkerSegmentBeforeForTest(
    allocator: std.mem.Allocator,
    stream: []const u8,
    moving_marker: u16,
    before_marker: u16,
) ![]u8 {
    const moving_start = findMarker(stream, moving_marker) orelse return error.MissingMarker;
    const moving_end = try markerSegmentEndForTest(stream, moving_start);
    const before_start = findMarker(stream, before_marker) orelse return error.MissingMarker;
    if (moving_start == before_start) return error.InvalidMarkerMove;

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    if (moving_start > before_start) {
        try out.appendSlice(allocator, stream[0..before_start]);
        try out.appendSlice(allocator, stream[moving_start..moving_end]);
        try out.appendSlice(allocator, stream[before_start..moving_start]);
        try out.appendSlice(allocator, stream[moving_end..]);
    } else {
        try out.appendSlice(allocator, stream[0..moving_start]);
        try out.appendSlice(allocator, stream[moving_end..before_start]);
        try out.appendSlice(allocator, stream[moving_start..moving_end]);
        try out.appendSlice(allocator, stream[before_start..]);
    }
    return out.toOwnedSlice(allocator);
}

fn moveMarkerSegmentAfterMarkerForTest(
    allocator: std.mem.Allocator,
    stream: []const u8,
    moving_marker: u16,
    after_marker: u16,
) ![]u8 {
    const moving_start = findMarker(stream, moving_marker) orelse return error.MissingMarker;
    const moving_end = try markerSegmentEndForTest(stream, moving_start);
    const after_start = findMarker(stream, after_marker) orelse return error.MissingMarker;
    if (moving_start == after_start) return error.InvalidMarkerMove;
    const after_end = after_start + 2;

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    if (moving_start > after_start) {
        try out.appendSlice(allocator, stream[0..after_end]);
        try out.appendSlice(allocator, stream[moving_start..moving_end]);
        try out.appendSlice(allocator, stream[after_end..moving_start]);
        try out.appendSlice(allocator, stream[moving_end..]);
    } else {
        try out.appendSlice(allocator, stream[0..moving_start]);
        try out.appendSlice(allocator, stream[moving_end..after_end]);
        try out.appendSlice(allocator, stream[moving_start..moving_end]);
        try out.appendSlice(allocator, stream[after_end..]);
    }
    return out.toOwnedSlice(allocator);
}

fn markerSegmentEndForTest(stream: []const u8, start: usize) !usize {
    if (stream.len - start < 4) return error.TruncatedMarkerSegment;
    const length = (@as(usize, stream[start + 2]) << 8) | stream[start + 3];
    if (length < 2 or stream.len - (start + 2) < length) return error.TruncatedMarkerSegment;
    return start + 2 + length;
}

test "uniform COC/QCC overrides across all components decode via the signalled values" {
    // Kakadu signals uniform per-component requests (Cmodes:C0..C2=RESET,
    // Qguard:C0..C2=2) as three identical COC/QCC markers whose values differ
    // from the main COD/QCD. The decoder must follow the override when every
    // component agrees, and fail closed when the set is partial or divergent.
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{ .allocator = allocator, .width = width, .height = height, .bit_depth = 8, .samples = samples };

    // --- COC style override oracle: encode with RESET so the payload really
    // uses context reset, then move the style bit from the COD into three
    // uniform COCs. Decode must follow the COC style to reconstruct.
    const reset_stream = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2, .reset_context = true });
    defer allocator.free(reset_stream);
    const cod = findMarker(reset_stream, codestream.markerValue("cod")) orelse return error.MissingCod;
    const cod_len = (@as(usize, reset_stream[cod + 2]) << 8) | reset_stream[cod + 3];
    // COD payload: Scod(1) SGcod(4) NL(1) xcb(1) ycb(1) style(1) transform...
    const cod_style_offset = cod + 4 + 8;
    try std.testing.expectEqual(@as(u8, 0x02), reset_stream[cod_style_offset]);

    var with_cocs = try allocator.dupe(u8, reset_stream);
    // Clear the COD style: the RESET signal now lives only in the COCs.
    with_cocs[cod_style_offset] = 0x00;
    const cod_scod = with_cocs[cod + 4];
    const cod_coding_len = cod_len - 2 - 5;
    var component: u8 = 0;
    while (component < 3) : (component += 1) {
        var coc_payload: std.ArrayList(u8) = .empty;
        defer coc_payload.deinit(allocator);
        try coc_payload.append(allocator, component);
        try coc_payload.append(allocator, cod_scod & 0x01);
        try coc_payload.appendSlice(allocator, with_cocs[cod + 4 + 5 ..][0..cod_coding_len]);
        coc_payload.items[2 + 3] = 0x02; // SPcoc style byte carries RESET
        const insert_at = cod + 4 + (cod_len - 2);
        const next = try spliceMarkerSegmentForTest(allocator, with_cocs, insert_at, codestream.markerValue("coc"), coc_payload.items);
        allocator.free(with_cocs);
        with_cocs = next;
    }
    defer allocator.free(with_cocs);

    {
        var decoded = try codestream.decodeLosslessTemporary(allocator, with_cocs);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, with_cocs);
        allocator.free(wrapped);
    }

    // Partial override (drop the third COC) must fail closed.
    {
        const third_coc_start = blk: {
            var offset: usize = 0;
            var found: usize = 0;
            while (findMarkerAfter(with_cocs, codestream.markerValue("coc"), offset)) |at| {
                found += 1;
                if (found == 3) break :blk at;
                offset = at + 2;
            }
            return error.MissingCoc;
        };
        const third_len = (@as(usize, with_cocs[third_coc_start + 2]) << 8) | with_cocs[third_coc_start + 3];
        var partial: std.ArrayList(u8) = .empty;
        defer partial.deinit(allocator);
        try partial.appendSlice(allocator, with_cocs[0..third_coc_start]);
        try partial.appendSlice(allocator, with_cocs[third_coc_start + 2 + third_len ..]);
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.decodeLosslessTemporary(allocator, partial.items),
        );
        try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, partial.items));
    }

    // Divergent override (one COC styles differently) must fail closed.
    {
        const divergent = try allocator.dupe(u8, with_cocs);
        defer allocator.free(divergent);
        const first_coc = findMarker(divergent, codestream.markerValue("coc")) orelse return error.MissingCoc;
        divergent[first_coc + 4 + 2 + 3] = 0x08; // CAUSAL on component 0 only
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.decodeLosslessTemporary(allocator, divergent),
        );
    }

    // --- QCC quantization override oracle: rewrite the QCD to the equivalent
    // guard-1 form (guard 2->1, exponents +1 keeps Mb identical), then hang
    // the original guard-2 values on three uniform QCCs. The decode must use
    // the QCC values; since both describe the same Mb the pixels must match.
    const base = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2 });
    defer allocator.free(base);
    const qcd = findMarker(base, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const qcd_len = (@as(usize, base[qcd + 2]) << 8) | base[qcd + 3];
    const qcd_payload_len = qcd_len - 2;

    var with_qccs = try allocator.dupe(u8, base);
    // Keep a copy of the original QCD payload for the QCC bodies.
    const original_qcd = try allocator.dupe(u8, base[qcd + 4 ..][0..qcd_payload_len]);
    defer allocator.free(original_qcd);
    // Rewrite QCD: guard 2 -> 1, every exponent +1 (equivalent Mb).
    with_qccs[qcd + 4] = 1 << 5;
    for (1..qcd_payload_len) |index| {
        with_qccs[qcd + 4 + index] += 8;
    }
    component = 0;
    while (component < 3) : (component += 1) {
        var qcc_payload: std.ArrayList(u8) = .empty;
        defer qcc_payload.deinit(allocator);
        try qcc_payload.append(allocator, component);
        try qcc_payload.appendSlice(allocator, original_qcd);
        const qcd_at = findMarker(with_qccs, codestream.markerValue("qcd")) orelse return error.MissingQcd;
        const insert_at = qcd_at + 4 + qcd_payload_len;
        const next = try spliceMarkerSegmentForTest(allocator, with_qccs, insert_at, codestream.markerValue("qcc"), qcc_payload.items);
        allocator.free(with_qccs);
        with_qccs = next;
    }
    defer allocator.free(with_qccs);

    {
        var decoded = try codestream.decodeLosslessTemporary(allocator, with_qccs);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, with_qccs);
        allocator.free(wrapped);
    }

    // A QCC override is only representable by the current uniform-component
    // decode path when all RGB components carry the same payload.
    {
        const third_qcc_start = blk: {
            var offset: usize = 0;
            var found: usize = 0;
            while (findMarkerAfter(with_qccs, codestream.markerValue("qcc"), offset)) |at| {
                found += 1;
                if (found == 3) break :blk at;
                offset = at + 2;
            }
            return error.MissingQcc;
        };
        const third_len = (@as(usize, with_qccs[third_qcc_start + 2]) << 8) | with_qccs[third_qcc_start + 3];
        var partial: std.ArrayList(u8) = .empty;
        defer partial.deinit(allocator);
        try partial.appendSlice(allocator, with_qccs[0..third_qcc_start]);
        try partial.appendSlice(allocator, with_qccs[third_qcc_start + 2 + third_len ..]);
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.decodeLosslessTemporary(allocator, partial.items),
        );
        try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, partial.items));
    }

    {
        const divergent = try allocator.dupe(u8, with_qccs);
        defer allocator.free(divergent);
        const first_qcc = findMarker(divergent, codestream.markerValue("qcc")) orelse return error.MissingQcc;
        divergent[first_qcc + 5] = 1 << 5; // component 0 uses guard 1; the others use guard 2
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.decodeLosslessTemporary(allocator, divergent),
        );
        try std.testing.expectError(jp2.Jp2Error.UnsupportedProfile, jp2.wrapRgbCodestream(allocator, rgb, divergent));
    }
}

test "precinct-less COD maps to maximal precincts and decodes byte-exactly" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    // Explicit maximal precincts produce the exact packet layout a
    // precinct-less COD implies (one precinct per resolution, ISO B.6).
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .precincts = [_]codestream.PrecinctSize{.{ .width = 32768, .height = 32768 }} ** 33,
        .precinct_count = 1,
    });
    defer allocator.free(bytes);

    // Splice the precinct bytes out of COD and clear Scod bit 0: the stream
    // now signals "no precinct partition" like OpenJPEG/Grok defaults do,
    // while every packet stays byte-identical.
    const cod = findMarker(bytes, codestream.markerValue("cod")) orelse return error.MissingCod;
    const levels = bytes[cod + 9];
    const removed: usize = @as(usize, levels) + 1;
    var spliced: std.ArrayList(u8) = .empty;
    defer spliced.deinit(allocator);
    try spliced.appendSlice(allocator, bytes[0 .. cod + 14]);
    try spliced.appendSlice(allocator, bytes[cod + 14 + removed ..]);
    const old_length = (@as(u16, spliced.items[cod + 2]) << 8) | spliced.items[cod + 3];
    const new_length = old_length - @as(u16, @intCast(removed));
    spliced.items[cod + 2] = @intCast(new_length >> 8);
    spliced.items[cod + 3] = @intCast(new_length & 0xff);
    spliced.items[cod + 4] &= ~@as(u8, 0x01);

    var decoded = try codestream.decodeLosslessTemporary(allocator, spliced.items);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    // The JP2 wrapper accepts the precinct-less profile too.
    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, spliced.items);
    allocator.free(wrapped);
}

test "foreign reversible QCD profiles decode via the signalled Mb" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2 });
    defer allocator.free(bytes);
    const qcd = findMarker(bytes, codestream.markerValue("qcd")) orelse return error.MissingQcd;
    const lqcd = readU16BeTest(bytes, qcd + 2);
    const exponent_count = @as(usize, lqcd) - 3;

    // Zero-bitplane signalling is relative to Mb = G + epsilon_b - 1 (E-2).
    // Rewriting guard bits and every exponent in opposite directions keeps
    // every band's Mb identical, so a decoder that truly follows the
    // signalled values reconstructs the exact pixels; foreign encoders
    // (Kakadu: G=1 with widened exponents) rely on this.
    const GuardShift = struct { guard: u8, exponent_delta: i16 };
    const rewrites = [_]GuardShift{
        .{ .guard = 1, .exponent_delta = 8 },
        .{ .guard = 3, .exponent_delta = -8 },
    };
    for (rewrites) |rewrite| {
        errdefer std.debug.print("QCD rewrite case failed: guard={}\n", .{rewrite.guard});
        const rewritten = try allocator.dupe(u8, bytes);
        defer allocator.free(rewritten);
        rewritten[qcd + 4] = rewrite.guard << 5;
        for (0..exponent_count) |index| {
            const offset = qcd + 5 + index;
            const updated = @as(i16, rewritten[offset]) + rewrite.exponent_delta;
            rewritten[offset] = @intCast(updated);
        }

        var decoded = try codestream.decodeLosslessTemporary(allocator, rewritten);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
    }
}

/// Removes every PLT segment from every tile-part, adjusting each SOT Psot
/// and the TLM entries (0x50 single-tile/R-parts or 0x60 multi-tile layout)
/// to match. The result is a PLT-less stream shaped like default
/// OpenJPEG/Grok output, driving the Stage B in-stream-order packet-header
/// span decoding.
fn stripAllPltForTest(allocator: std.mem.Allocator, bytes: []const u8) ![]u8 {
    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, bytes[0..first_sot]);

    var removed_per_part: [64]u32 = undefined;
    var part_count: usize = 0;
    var cursor = first_sot;
    while (cursor + 2 <= bytes.len and readU16BeTest(bytes, cursor) == codestream.markerValue("sot")) {
        const psot = readU32BeTest(bytes, cursor + 6);
        const part_end = cursor + @as(usize, psot);
        if (part_end > bytes.len) return error.InvalidStream;
        const sot_out_offset = out.items.len;
        try out.appendSlice(allocator, bytes[cursor .. cursor + 12]);

        var scan = cursor + 12;
        var removed: u32 = 0;
        while (scan + 2 <= part_end and readU16BeTest(bytes, scan) != codestream.markerValue("sod")) {
            const segment_total = 2 + @as(usize, readU16BeTest(bytes, scan + 2));
            if (scan + segment_total > part_end) return error.InvalidStream;
            if (readU16BeTest(bytes, scan) == codestream.markerValue("plt")) {
                removed += @intCast(segment_total);
            } else {
                try out.appendSlice(allocator, bytes[scan .. scan + segment_total]);
            }
            scan += segment_total;
        }
        try out.appendSlice(allocator, bytes[scan..part_end]);
        writeU32BeTest(out.items, sot_out_offset + 6, psot - removed);
        if (part_count >= removed_per_part.len) return error.InvalidStream;
        removed_per_part[part_count] = removed;
        part_count += 1;
        cursor = part_end;
    }
    try out.appendSlice(allocator, bytes[cursor..]);

    if (findMarker(out.items[0..first_sot], codestream.markerValue("tlm"))) |tlm| {
        const stlm = out.items[tlm + 5];
        const entry_size: usize = switch (stlm) {
            0x50 => 5,
            0x60 => 6,
            else => return error.InvalidTlm,
        };
        const ptlm_offset: usize = if (stlm == 0x50) 1 else 2;
        var entry = tlm + 6;
        for (removed_per_part[0..part_count]) |removed| {
            writeU32BeTest(out.items, entry + ptlm_offset, readU32BeTest(out.items, entry + ptlm_offset) - removed);
            entry += entry_size;
        }
    }
    return out.toOwnedSlice(allocator);
}

fn reorderTilePartsForTest(allocator: std.mem.Allocator, bytes: []const u8, order: []const usize) ![]u8 {
    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    var starts: [256]usize = undefined;
    var ends: [256]usize = undefined;
    var count: usize = 0;
    var cursor = first_sot;
    while (cursor + 2 <= bytes.len and readU16BeTest(bytes, cursor) == codestream.markerValue("sot")) {
        if (count >= starts.len) return error.TooManyTileParts;
        const psot = readU32BeTest(bytes, cursor + 6);
        const part_end = cursor + @as(usize, psot);
        if (part_end > bytes.len) return error.InvalidStream;
        starts[count] = cursor;
        ends[count] = part_end;
        count += 1;
        cursor = part_end;
    }
    if (order.len != count) return error.InvalidOrder;

    var out: std.ArrayList(u8) = .empty;
    errdefer out.deinit(allocator);
    try out.appendSlice(allocator, bytes[0..first_sot]);
    var seen = [_]bool{false} ** 256;
    for (order) |index| {
        if (index >= count or seen[index]) return error.InvalidOrder;
        seen[index] = true;
        try out.appendSlice(allocator, bytes[starts[index]..ends[index]]);
    }
    try out.appendSlice(allocator, bytes[cursor..]);
    return out.toOwnedSlice(allocator);
}

test "PLT-less streams decode via in-stream-order packet header spans" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    // Small explicit precincts force several precincts per resolution, so the
    // non-RPCL cases genuinely interleave per-precinct reader states across
    // the stream; block 8 <= precinct/2 keeps B.7 satisfied.
    const small_precincts = [_]codestream.PrecinctSize{.{ .width = 16, .height = 16 }} ** 33;

    const Case = struct {
        label: []const u8,
        options: codestream.LosslessOptions,
    };
    const cases = [_]Case{
        // R tile-part divisions: the PLT-less walk must continue the packet
        // sequence seamlessly across tile-part boundaries.
        .{ .label = "RPCL R-parts", .options = .{ .levels = 2, .block_width = 8, .block_height = 8, .precincts = small_precincts, .precinct_count = 1 } },
        // Multi-layer LRCP: precincts revisited across layers — the stateful
        // per-precinct decode is what makes the spans recoverable.
        .{ .label = "LRCP 2 layers", .options = .{ .levels = 2, .layers = 2, .progression = .lrcp, .block_width = 8, .block_height = 8, .precincts = small_precincts, .precinct_count = 1 } },
        // Position-ordered progression exercises the sorted stream sequence.
        .{ .label = "PCRL", .options = .{ .levels = 2, .progression = .pcrl, .block_width = 8, .block_height = 8, .precincts = small_precincts, .precinct_count = 1 } },
        // BYPASS emits multi-segment packet-header lengths (B.10.7.2).
        .{ .label = "BYPASS", .options = .{ .levels = 2, .bypass = true, .block_width = 8, .block_height = 8, .precincts = small_precincts, .precinct_count = 1 } },
        // EPH sits between the packet header and the body; the span walk must
        // hop it. Also drop TLM so the no-TLM main header path is covered.
        .{ .label = "EPH no-TLM", .options = .{ .levels = 2, .eph = true, .tlm = false, .block_width = 8, .block_height = 8, .precincts = small_precincts, .precinct_count = 1 } },
    };

    for (cases) |scenario| {
        errdefer std.debug.print("PLT-less case failed: {s}\n", .{scenario.label});
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, scenario.options);
        defer allocator.free(bytes);
        const stripped = try stripAllPltForTest(allocator, bytes);
        defer allocator.free(stripped);
        try std.testing.expect(findMarker(stripped, codestream.markerValue("plt")) == null);

        var decoded = try codestream.decodeLosslessTemporary(allocator, stripped);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

        // The audit path uses the same catalog and must agree with the plan.
        const audit = try codestream.auditStrictPacketHeaders(allocator, stripped);
        try std.testing.expect(audit.packets > 0);
        try std.testing.expectEqual(audit.packets, audit.header_decoded_packets);
    }
}

test "corrupted PLT-less packet header fails with a bounded error" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2, .block_width = 8, .block_height = 8 });
    defer allocator.free(bytes);
    const stripped = try stripAllPltForTest(allocator, bytes);
    defer allocator.free(stripped);

    // Without PLT the packet spans come entirely from the decoded headers, so
    // flipping bytes just past the first SOD must never panic or read out of
    // bounds — every corruption either decodes to wrong-but-bounded output or
    // reports a bounded error, and at least one byte must be rejected.
    const first_sod = findMarker(stripped, codestream.markerValue("sod")) orelse return error.MissingSod;
    var rejected = false;
    var offset = first_sod + 2;
    while (offset < first_sod + 18 and offset < stripped.len) : (offset += 1) {
        const corrupted = try allocator.dupe(u8, stripped);
        defer allocator.free(corrupted);
        corrupted[offset] ^= 0x5a;
        if (codestream.decodeLosslessTemporary(allocator, corrupted)) |decoded_image| {
            var owned = decoded_image;
            owned.deinit();
        } else |_| {
            rejected = true;
        }
    }
    try std.testing.expect(rejected);
}

test "PCRD allocator prefers high-slope passes and respects layer budgets" {
    const allocator = std.testing.allocator;

    // Block A: cheap bytes, large distortion reductions (steep slopes).
    // Block B: same byte layout, tiny distortion reductions (shallow slopes).
    const bytes_a = [_]u64{ 10, 20, 30 };
    const dist_a = [_]f64{ 9000, 3000, 1000 };
    const bytes_b = [_]u64{ 10, 20, 30 };
    const dist_b = [_]f64{ 90, 30, 10 };
    const blocks = [_]rate_alloc.PcrdBlock{
        .{ .pass_bytes = &bytes_a, .pass_distortion = &dist_a },
        .{ .pass_bytes = &bytes_b, .pass_distortion = &dist_b },
    };

    // Layer 0 budget fits exactly one block's full payload plus one pass of
    // the other; the steep block must win every contested slot. Layer 1 is
    // the full stream.
    const targets = [_]u64{ 40, 60 };
    var out: [4]u16 = undefined;
    try rate_alloc.allocatePcrdPasses(allocator, &blocks, &targets, &out);

    // Block-major layout: [block0 layer0, block0 layer1, block1 layer0, ...].
    try std.testing.expectEqual(@as(u16, 3), out[0]);
    try std.testing.expectEqual(@as(u16, 3), out[1]);
    try std.testing.expect(out[2] <= 1);
    try std.testing.expectEqual(@as(u16, 3), out[3]);

    // Selections never regress across layers and the layer-0 total fits.
    var layer0_total: u64 = 0;
    if (out[0] > 0) layer0_total += bytes_a[out[0] - 1];
    if (out[2] > 0) layer0_total += bytes_b[out[2] - 1];
    try std.testing.expect(layer0_total <= targets[0]);
}

test "PCRD rate allocation is deterministic across encode thread counts" {
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    var seed: u32 = 12345;
    for (0..width * height) |i| {
        seed = seed *% 1664525 +% 1013904223;
        samples[i * 3 + 0] = @intCast((seed >> 8) & 0xff);
        samples[i * 3 + 1] = @intCast((seed >> 16) & 0xff);
        samples[i * 3 + 2] = @intCast((seed >> 24) & 0xff);
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = codestream.LosslessOptions{ .levels = 2, .block_width = 16, .block_height = 16 };
    const rates = [_]f64{ 20, 4 };
    @memcpy(options.rates[0..rates.len], &rates);
    options.rate_count = rates.len;
    options.layers = 3;

    options.threads = 1;
    const single = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(single);
    options.threads = 4;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, single, threaded);

    // The full stream still reconstructs losslessly (final layer is full).
    var decoded = try codestream.decodeLosslessTemporary(allocator, single);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
}

test "rate-driven layers work on the irreversible 9/7 path" {
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |row| {
        for (0..width) |col| {
            const i = row * width + col;
            samples[i * 3 + 0] = @intCast((col * 4) % 256);
            samples[i * 3 + 1] = @intCast((row * 4) % 256);
            samples[i * 3 + 2] = @intCast((col * 2 + row * 2) % 256);
        }
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = codestream.LosslessOptions{
        .levels = 3,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
        .bypass = true,
    };
    const rates = [_]f64{ 100, 50, 20, 8 };
    @memcpy(options.rates[0..rates.len], &rates);
    options.rate_count = rates.len;
    options.layers = rates.len;

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);
    const stats = try codestream.analyzeLosslessTemporary(bytes);
    try std.testing.expectEqual(@as(u16, 4), stats.layers);

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{});
    defer decoded.deinit();
    var max_diff: i32 = 0;
    for (samples, decoded.samples) |expected, actual| {
        const diff = @as(i32, expected) - @as(i32, actual);
        max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
    }
    try std.testing.expect(max_diff <= 8);
}

test "rate-targeted layer byte accounting stays pinned on the PCRD corpus" {
    // Mirrors tools/pcrd_psnr_ladder.ps1: the same 256x256 integer-only
    // mixed corpus (smooth gradient / sawtooth / checkerboard+hash-noise),
    // 9/7 ICT with five LRCP quality layers targeted at compression ratios
    // 80/40/20/10 of the total compressed payload (the final layer is always
    // complete). LRCP keeps the layer as the outermost packet loop, so the
    // per-layer PLT prefix sums are the assembled layer payload sizes; the
    // global PCRD allocator plus packet-header charging must land each
    // cumulative layer size on its byte target. The reference-relative
    // quality of these truncation points is measured out-of-process by the
    // ladder tool (2026-07-11: 0.7-1.8 dB behind OpenJPEG at matched bytes).
    const allocator = std.testing.allocator;
    const width = 256;
    const height = 256;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |y| {
        for (0..width) |x| {
            const i = (y * width + x) * 3;
            samples[i + 0] = @intCast((x + y) >> 1);
            samples[i + 1] = @intCast(((x % 64) * 4 + (y % 32) * 2) & 0xff);
            const checker: u64 = if (((x / 32) + (y / 32)) % 2 == 0) 200 else 56;
            const noise = (((@as(u64, x) * 73856093) ^ (@as(u64, y) * 19349663)) >> 13) & 15;
            samples[i + 2] = @intCast((checker + noise) & 0xff);
        }
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = codestream.LosslessOptions{
        .levels = 5,
        .transform = .irreversible_9_7,
        .mct = .ict,
        .quantization = .scalar_expounded,
        .progression = .lrcp,
        .sop = false,
        .tlm = false,
        .tile_part_divisions = null,
    };
    const rates = [_]f64{ 80, 40, 20, 10, 5 };
    @memcpy(options.rates[0..rates.len], &rates);
    options.rate_count = rates.len;
    options.layers = rates.len;

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    // Byte-deterministic across encode thread counts.
    var threaded_options = options;
    threaded_options.threads = 3;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    // Collect the PLT packet lengths of the single tile-part in stream order.
    var packet_lengths: std.ArrayList(u64) = .empty;
    defer packet_lengths.deinit(allocator);
    {
        const plt_marker = codestream.markerValue("plt");
        const sod = codestream.markerValue("sod");
        const sot = codestream.markerValue("sot");
        var cursor: usize = 2;
        while (readU16BeTest(bytes, cursor) != sot) {
            cursor += 2 + readU16BeTest(bytes, cursor + 2);
        }
        cursor += 12;
        while (readU16BeTest(bytes, cursor) != sod) {
            const marker_value = readU16BeTest(bytes, cursor);
            const segment_length = readU16BeTest(bytes, cursor + 2);
            if (marker_value == plt_marker) {
                var value: u64 = 0;
                for (bytes[cursor + 5 .. cursor + 2 + segment_length]) |byte| {
                    value = (value << 7) | (byte & 0x7f);
                    if ((byte & 0x80) == 0) {
                        try packet_lengths.append(allocator, value);
                        value = 0;
                    }
                }
            }
            cursor += 2 + segment_length;
        }
    }
    try std.testing.expectEqual(@as(usize, 0), packet_lengths.items.len % rates.len);
    const packets_per_layer = packet_lengths.items.len / rates.len;

    var total_packet_bytes: u64 = 0;
    for (packet_lengths.items) |length| total_packet_bytes += length;

    // Every intermediate cumulative layer size must land near its target
    // (total payload / ratio). The allocator charges measured packet-header
    // bytes against the targets, so actual sizes sit at or slightly under
    // them; 15% covers pass-boundary snapping on this corpus.
    var cumulative: u64 = 0;
    for (0..rates.len - 1) |layer| {
        var layer_sum: u64 = 0;
        for (0..packets_per_layer) |k| layer_sum += packet_lengths.items[layer * packets_per_layer + k];
        cumulative += layer_sum;
        const target = @as(f64, @floatFromInt(total_packet_bytes)) / rates[layer];
        const actual = @as(f64, @floatFromInt(cumulative));
        errdefer std.debug.print(
            "layer {} cumulative {} target {d:.0} (total {})\n",
            .{ layer + 1, cumulative, target, total_packet_bytes },
        );
        try std.testing.expect(@abs(actual - target) <= target * 0.15);
    }

    // Full-stream reconstruction quality floor (measured 51.7 dB, max 3).
    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    var sse: u64 = 0;
    var max_diff: u32 = 0;
    for (samples, decoded.samples) |expected, actual| {
        const delta = @abs(@as(i32, @intCast(expected)) - @as(i32, @intCast(actual)));
        max_diff = @max(max_diff, @as(u32, @intCast(delta)));
        sse += @as(u64, @intCast(delta * delta));
    }
    try std.testing.expect(max_diff <= 4);
    const mse = @as(f64, @floatFromInt(sse)) / @as(f64, @floatFromInt(samples.len));
    const psnr = 10.0 * std.math.log10(255.0 * 255.0 / mse);
    try std.testing.expect(psnr >= 51.0);
}

test "multi-layer BYPASS codestream roundtrips losslessly (NDK MC style)" {
    const allocator = std.testing.allocator;
    const width = 96;
    const height = 96;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    var seed: u32 = 777;
    for (samples) |*sample| {
        seed = seed *% 1664525 +% 1013904223;
        sample.* = @intCast((seed >> 16) & 0xff);
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    // Plain 12 layers with even pass allocation snapped to segment ends.
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .layers = 12,
        .bypass = true,
    });
    defer allocator.free(bytes);

    const stats = try codestream.analyzeLosslessTemporary(bytes);
    try std.testing.expectEqual(@as(u16, 12), stats.layers);

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{});
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, samples, decoded.samples);

    // Rate-driven layering (NDK MC style compression ratios) with bypass.
    var rated_options = codestream.LosslessOptions{
        .levels = 3,
        .bypass = true,
    };
    const ndk_rates = [_]f64{ 362, 256, 181, 128, 90, 64, 45, 32, 22, 16, 11, 8 };
    @memcpy(rated_options.rates[0..ndk_rates.len], &ndk_rates);
    rated_options.rate_count = ndk_rates.len;
    rated_options.layers = ndk_rates.len;

    const rated = try codestream.encodeLosslessWithOptions(allocator, rgb, rated_options);
    defer allocator.free(rated);
    var rated_decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, rated, .{});
    defer rated_decoded.deinit();
    try std.testing.expectEqualSlices(u16, samples, rated_decoded.samples);
}

test "BYPASS codestream roundtrips losslessly through strict SOD packets" {
    const allocator = std.testing.allocator;
    const width = 96;
    const height = 96;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    var seed: u32 = 424242;
    for (samples) |*sample| {
        seed = seed *% 1664525 +% 1013904223;
        sample.* = @intCast((seed >> 16) & 0xff);
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
        .bypass = true,
    });
    defer allocator.free(bytes);
    try std.testing.expect(std.mem.indexOf(u8, bytes, "ZJ2K-CBLK-BP8") == null);

    var catalog = try codestream.readStrictPacketBlockCatalog(allocator, bytes);
    defer catalog.deinit();
    var bypass_blocks: usize = 0;
    var segmented_bypass_blocks: usize = 0;
    for (catalog.components) |blocks| {
        for (blocks) |block| {
            if (!block.metadata_ready) continue;
            if (!block.code_block_style.bypass) continue;
            bypass_blocks += 1;
            if (block.segment_count > 1) segmented_bypass_blocks += 1;
            try std.testing.expect(block.payload_length > 0);
            try std.testing.expect(block.cumulative_passes > 0);
        }
    }
    try std.testing.expect(bypass_blocks > 0);
    try std.testing.expect(segmented_bypass_blocks > 0);

    var decoded = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{});
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, samples, decoded.samples);

    // The same content without bypass must produce a different codestream
    // (COD style byte plus segment layout).
    const plain = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 3,
    });
    defer allocator.free(plain);
    try std.testing.expect(!std.mem.eql(u8, bytes, plain));
}

test "BYPASS T1 segments roundtrip through the segment coder pair" {
    const allocator = std.testing.allocator;
    const w = 32;
    const h = 32;
    var plane: [w * h]i32 = undefined;
    var seed: u32 = 12345;
    for (&plane) |*value| {
        seed = seed *% 1664525 +% 1013904223;
        const magnitude: i32 = @intCast((seed >> 8) & 0x1ff);
        value.* = if ((seed & 1) == 1) -magnitude else magnitude;
    }

    const style = ebcot.CodeBlockStyle{ .band_kind = .hh, .bypass = true };
    var block = try ebcot.encodeBlockWithStyle(allocator, &plane, w, .{ .x = 0, .y = 0, .width = w, .height = h }, style);
    defer block.deinit(allocator);
    var segment = try ebcot.encodeBlockSymbolsSegmentIsoMqBypass(allocator, .{
        .bitplanes = block.bitplanes,
        .non_zero_count = block.non_zero_count,
        .passes = block.passes,
        .symbols = block.symbols,
    }, style);
    defer segment.deinit(allocator);

    const segments = segment.segments orelse return error.TestUnexpectedResult;
    try std.testing.expect(segments.len > 1);
    var lengths: [ebcot.max_block_segments]u64 = undefined;
    for (segments, 0..) |span, index| lengths[index] = span.byte_length;

    var scratch = ebcot.DecodeBlockScratch.init(allocator);
    defer scratch.deinit();
    const decoded = try ebcot.decodeCodeBlockPayloadBypassIsoMqScratchWithStyle(
        &scratch,
        segment.bitplanes,
        segment.pass_count,
        segment.bytes,
        lengths[0..segments.len],
        w,
        h,
        style,
    );
    defer allocator.free(decoded);
    try std.testing.expectEqualSlices(i32, &plane, decoded);
}

test "ISO MQ multi-layer codestream decodes from strict SOD packets" {
