        samples[i * 3 + 0] = @as(u16, @intCast((i * 19 + 7) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 13 + 41) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 3 + 97) % 256));
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
