test "predictable termination roundtrips losslessly and changes the flush" {
    const allocator = std.testing.allocator;
    const width = 16;
    const height = 16;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const erterm = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .terminate_all = true,
        .predictable_termination = true,
    });
    defer allocator.free(erterm);
    const termall = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .terminate_all = true,
    });
    defer allocator.free(termall);

    // The COD code-block-style byte must advertise ERTERM (0x10) together
    // with TERMALL (0x04) only when predictable termination is requested.
    const erterm_cod = findMarker(erterm, codestream.markerValue("cod")) orelse return error.MissingCod;
    const termall_cod = findMarker(termall, codestream.markerValue("cod")) orelse return error.MissingCod;
    try std.testing.expectEqual(@as(u8, 0x14), erterm[erterm_cod + 12] & 0x14);
    try std.testing.expectEqual(@as(u8, 0x04), termall[termall_cod + 12] & 0x14);

    // The ER-TERM flush produces a different (predictable) byte layout.
    try std.testing.expect(!std.mem.eql(u8, erterm, termall));

    // Encoding stays deterministic and the stream reconstructs byte-exactly.
    const erterm_again = try codestream.encodeLosslessWithOptions(allocator, rgb, .{
        .levels = 2,
        .terminate_all = true,
        .predictable_termination = true,
    });
    defer allocator.free(erterm_again);
    try std.testing.expectEqualSlices(u8, erterm, erterm_again);

    var decoded = try codestream.decodeLosslessTemporary(allocator, erterm);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    var threaded = try codestream.decodeLosslessTemporaryWithOptions(allocator, erterm, .{ .threads = 4 });
    defer threaded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, threaded.samples);

    // The JP2 wrapper accepts the ERTERM+TERMALL profile.
    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, erterm);
    allocator.free(wrapped);
}

test "standalone predictable termination roundtrips losslessly and changes the flush" {
    // ISO 15444-1 D.4.2: with ERTERM (0x10) and no TERMALL, the only
    // termination point in a continuous MQ code-block is the final flush,
    // which must use the predictable ER-TERM procedure. The stream still
    // decodes through the ordinary continuous path because the spilled
    // register bits equal the byte-in padding a decoder supplies.
    const allocator = std.testing.allocator;
    const width = 16;
    const height = 16;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const Scenario = struct { label: []const u8, options: codestream.LosslessOptions, cod_style: u8 };
    const scenarios = [_]Scenario{
        .{
            .label = "ERTERM",
            .options = .{ .levels = 2, .predictable_termination = true },
            .cod_style = 0x10,
        },
        .{
            .label = "ERTERM+RESET",
            .options = .{ .levels = 2, .predictable_termination = true, .reset_context = true },
            .cod_style = 0x12,
        },
    };

    const plain = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2 });
    defer allocator.free(plain);

    for (scenarios) |scenario| {
        errdefer std.debug.print("standalone ERTERM scenario failed: {s}\n", .{scenario.label});
        const erterm = try codestream.encodeLosslessWithOptions(allocator, rgb, scenario.options);
        defer allocator.free(erterm);

        const cod = findMarker(erterm, codestream.markerValue("cod")) orelse return error.MissingCod;
        try std.testing.expectEqual(scenario.cod_style, erterm[cod + 12]);

        // The ER-TERM flush produces a different byte layout than the
        // standard flush of the otherwise identical stream.
        try std.testing.expect(!std.mem.eql(u8, erterm, plain));

        // Encoding stays deterministic.
        const again = try codestream.encodeLosslessWithOptions(allocator, rgb, scenario.options);
        defer allocator.free(again);
        try std.testing.expectEqualSlices(u8, erterm, again);

        var decoded = try codestream.decodeLosslessTemporary(allocator, erterm);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

        var threaded = try codestream.decodeLosslessTemporaryWithOptions(allocator, erterm, .{ .threads = 4 });
        defer threaded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, threaded.samples);

        // The JP2 wrapper accepts the standalone ERTERM profile.
        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, erterm);
        allocator.free(wrapped);
    }

    // Multi-tile standalone RESET/ERTERM coverage lives in "multi-tile
    // standalone reset and predictable termination roundtrip losslessly".
}

test "bypass reset and predictable termination roundtrip losslessly" {
    // Non-TERMALL BYPASS carries RESET and ERTERM now: RESET restarts the MQ
    // contexts at every coding-pass boundary of the MQ segments (raw
    // segments carry no contexts), and ERTERM terminates every raw/MQ
    // segment predictably (alternating-bit raw padding, ER-TERM MQ flush).
    const allocator = std.testing.allocator;
    const width = 16;
    const height = 16;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const Scenario = struct { label: []const u8, options: codestream.LosslessOptions, cod_style: u8 };
    const scenarios = [_]Scenario{
        .{
            .label = "BYPASS+RESET",
            .options = .{ .levels = 2, .bypass = true, .reset_context = true },
            .cod_style = 0x03,
        },
        .{
            .label = "BYPASS+ERTERM",
            .options = .{ .levels = 2, .bypass = true, .predictable_termination = true },
            .cod_style = 0x11,
        },
        .{
            .label = "BYPASS+RESET+ERTERM",
            .options = .{ .levels = 2, .bypass = true, .reset_context = true, .predictable_termination = true },
            .cod_style = 0x13,
        },
        .{
            .label = "BYPASS+RESET+TERMALL",
            .options = .{ .levels = 2, .bypass = true, .terminate_all = true, .reset_context = true },
            .cod_style = 0x07,
        },
        .{
            .label = "BYPASS+ERTERM+TERMALL",
            .options = .{ .levels = 2, .bypass = true, .terminate_all = true, .predictable_termination = true },
            .cod_style = 0x15,
        },
        .{
            .label = "all six style bits",
            .options = .{
                .levels = 2,
                .bypass = true,
                .reset_context = true,
                .terminate_all = true,
                .vertical_causal = true,
                .predictable_termination = true,
                .segmentation_symbols = true,
            },
            .cod_style = 0x3f,
        },
    };

    const plain_bypass = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2, .bypass = true });
    defer allocator.free(plain_bypass);

    for (scenarios) |scenario| {
        errdefer std.debug.print("bypass style scenario failed: {s}\n", .{scenario.label});
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, scenario.options);
        defer allocator.free(bytes);

        const cod = findMarker(bytes, codestream.markerValue("cod")) orelse return error.MissingCod;
        try std.testing.expectEqual(scenario.cod_style, bytes[cod + 12]);

        // RESET changes the MQ statistics and ERTERM changes the segment
        // flush bytes, so each stream must differ from plain BYPASS.
        try std.testing.expect(!std.mem.eql(u8, bytes, plain_bypass));

        const again = try codestream.encodeLosslessWithOptions(allocator, rgb, scenario.options);
        defer allocator.free(again);
        try std.testing.expectEqualSlices(u8, bytes, again);

        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

        var threaded = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{ .threads = 4 });
        defer threaded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, threaded.samples);

        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
        allocator.free(wrapped);
    }
}

