/// Fuzzes one codestream and its JP2 wrapper against truncation at every
/// length and single-byte corruption (values 0xff/0x00) at every
/// `corruption_step`-th position. An OOB read or unchecked slice would abort
/// the test binary under Debug/ReleaseSafe bounds checks (ReleaseFast would
/// corrupt or crash), so simply returning is the assertion: no panic, no
/// out-of-bounds. Errors are caught and ignored. An arena reset per attempt
/// bounds memory.
fn fuzzCorruptionSweep(
    base_allocator: std.mem.Allocator,
    codestream_bytes: []const u8,
    wrapped: []const u8,
    truncation_step: usize,
    corruption_step: usize,
) !void {
    var arena = std.heap.ArenaAllocator.init(base_allocator);
    defer arena.deinit();
    const a = arena.allocator();

    const Case = struct { bytes: []const u8, jp2: bool };
    const targets = [_]Case{ .{ .bytes = codestream_bytes, .jp2 = false }, .{ .bytes = wrapped, .jp2 = true } };

    for (targets) |target| {
        const n = target.bytes.len;

        var len: usize = 0;
        while (len <= n) : (len += truncation_step) {
            _ = arena.reset(.retain_capacity);
            const buf = try a.dupe(u8, target.bytes[0..len]);
            if (target.jp2) {
                _ = jp2.parseInfo(buf) catch {};
                if (jp2.extractCodestream(buf)) |cs| {
                    _ = codestream.decodeLosslessTemporary(a, cs) catch {};
                } else |_| {}
            } else {
                _ = codestream.decodeLosslessTemporary(a, buf) catch {};
            }
        }

        for ([_]u8{ 0xff, 0x00 }) |value| {
            var i: usize = 0;
            while (i < n) : (i += corruption_step) {
                _ = arena.reset(.retain_capacity);
                const buf = try a.dupe(u8, target.bytes);
                buf[i] = value;
                if (target.jp2) {
                    _ = jp2.parseInfo(buf) catch {};
                    if (jp2.extractCodestream(buf)) |cs| {
                        _ = codestream.decodeLosslessTemporary(a, cs) catch {};
                    } else |_| {}
                } else {
                    _ = codestream.decodeLosslessTemporary(a, buf) catch {};
                }
            }
        }
    }
}

fn fillFuzzSamples(samples: []u16, salt: u32) void {
    var seed: u32 = 0x9e3779b9 ^ salt;
    for (samples) |*s| {
        seed = seed *% 1664525 +% 1013904223;
        s.* = @intCast((seed >> 15) & 0xff);
    }
}

test "malformed codestream corruption sweep never panics or reads out of bounds" {
    const base_allocator = std.testing.allocator;

    // Profile 1: single-tile archival RCT/5-3 with SOP+EPH+TLM. A 16x16 image
    // with 8x8 blocks and two resolutions keeps every parse surface present
    // (SIZ/COD/QCD, TLM, SOT/SOD, PLT, SOP/EPH framing, packet headers,
    // tag-trees, T1) while staying small enough to sweep byte by byte. The
    // gate is code-path coverage, not data volume.
    {
        const samples = try base_allocator.alloc(u16, 16 * 16 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 1);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 16, .height = 16, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{ .levels = 2, .block_width = 8, .block_height = 8, .sop = true, .eph = true, .tlm = true });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 1, 2);
    }

    // Profile 2: multi-tile RCT/5-3 (48x48, 2x2 grid of 32x32 tiles, 8x8
    // precincts, 4x4 blocks). Exercises the per-tile SOT walk, per-tile PLT,
    // and the multi-tile strict decode path, which have more parsing than the
    // single-tile path. Larger codestream, so sample corruption more coarsely.
    {
        const samples = try base_allocator.alloc(u16, 48 * 48 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 2);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 48, .height = 48, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 2,
            .tile_width = 32,
            .tile_height = 32,
            .block_width = 4,
            .block_height = 4,
            .precincts = [_]codestream.PrecinctSize{.{ .width = 8, .height = 8 }} ** 33,
            .precinct_count = 1,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 24, 24);
    }

    // Profile 3: irreversible ICT/9-7 with scalar-expounded QCD. Exercises the
    // 9/7 QCD step-size parsing and the float inverse-DWT/ICT decode path.
    {
        const samples = try base_allocator.alloc(u16, 16 * 16 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 3);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 16, .height = 16, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 3,
            .transform = .irreversible_9_7,
            .mct = .ict,
            .quantization = .scalar_expounded,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 4, 4);
    }

    // Profile 4: terminate-all (TERMALL) code-block style. Exercises the
    // per-pass terminated-segment T1 decoder and the multi-segment PLT/packet
    // path, which the plain-style profiles above never reach.
    {
        const samples = try base_allocator.alloc(u16, 24 * 24 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 4);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 24, .height = 24, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 2,
            .block_width = 8,
            .block_height = 8,
            .terminate_all = true,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 4, 4);
    }

    // Profile 5: BYPASS+TERMALL. This mixes raw bypass significance/refinement
    // segments with per-pass terminated MQ cleanup segments.
    {
        const samples = try base_allocator.alloc(u16, 24 * 24 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 5);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 24, .height = 24, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 2,
            .block_width = 8,
            .block_height = 8,
            .bypass = true,
            .terminate_all = true,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 4, 4);
    }

    // Profile 6: multi-tile TERMALL. Exercises per-tile packet walks together
    // with per-pass terminated segment lengths in the strict multi-tile path.
    {
        const samples = try base_allocator.alloc(u16, 48 * 48 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 6);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 48, .height = 48, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 2,
            .tile_width = 32,
            .tile_height = 32,
            .block_width = 4,
            .block_height = 4,
            .precincts = [_]codestream.PrecinctSize{.{ .width = 8, .height = 8 }} ** 33,
            .precinct_count = 1,
            .terminate_all = true,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 32, 32);
    }

    // Profile 7: multi-tile BYPASS+TERMALL. Exercises the strict per-tile T2
    // walk with raw significance/refinement and MQ cleanup segments together.
    {
        const samples = try base_allocator.alloc(u16, 48 * 48 * 3);
        defer base_allocator.free(samples);
        fillFuzzSamples(samples, 7);
        const rgb = image.RgbImage{ .allocator = base_allocator, .width = 48, .height = 48, .bit_depth = 8, .samples = samples };
        const cs = try codestream.encodeLosslessWithOptions(base_allocator, rgb, .{
            .levels = 2,
            .tile_width = 32,
            .tile_height = 32,
            .block_width = 4,
            .block_height = 4,
            .precincts = [_]codestream.PrecinctSize{.{ .width = 8, .height = 8 }} ** 33,
            .precinct_count = 1,
            .progression = .cprl,
            .tile_part_divisions = null,
            .bypass = true,
            .terminate_all = true,
            .sop = true,
            .eph = true,
            .tlm = true,
        });
        defer base_allocator.free(cs);
        const wrapped = try jp2.wrapRgbCodestream(base_allocator, rgb, cs);
        defer base_allocator.free(wrapped);
        try fuzzCorruptionSweep(base_allocator, cs, wrapped, 32, 32);
    }
}

test "terminated styled T1 streams fail closed on corruption" {
    const allocator = std.testing.allocator;
    // A varied 24x24 image with 8x8 blocks and two levels produces several
    // per-pass terminated segments per block, so each style below carries a
    // real multi-segment PLT and payload for the corruption matrix.
    const width = 24;
    const height = 24;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const Style = struct { label: []const u8, options: codestream.LosslessOptions };
    const base = codestream.LosslessOptions{ .levels = 2, .block_width = 8, .block_height = 8 };
    var termall = base;
    termall.terminate_all = true;
    var reset_termall = base;
    reset_termall.terminate_all = true;
    reset_termall.reset_context = true;
    var erterm = base;
    erterm.terminate_all = true;
    erterm.predictable_termination = true;
    var bypass_termall = base;
    bypass_termall.bypass = true;
    bypass_termall.terminate_all = true;
    const styles = [_]Style{
        .{ .label = "TERMALL", .options = termall },
        .{ .label = "RESET+TERMALL", .options = reset_termall },
        .{ .label = "ERTERM", .options = erterm },
        .{ .label = "BYPASS+TERMALL", .options = bypass_termall },
    };

    for (styles) |style| {
        errdefer std.debug.print("terminated corruption style failed: {s}\n", .{style.label});
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, style.options);
        defer allocator.free(bytes);

        // Sanity: the intact stream roundtrips.
        {
            var ok = try codestream.decodeLosslessTemporary(allocator, bytes);
            defer ok.deinit();
            try std.testing.expectEqualSlices(u16, samples, ok.samples);
        }

        // Corrupting the last per-pass PLT length byte breaks the terminated
        // segment-span accounting deterministically (packet length no longer
        // matches the SOD payload span).
        {
            const corrupted = try allocator.dupe(u8, bytes);
            defer allocator.free(corrupted);
            const plt = findMarker(corrupted, codestream.markerValue("plt")) orelse return error.MissingPlt;
            const segment_length = readU16BeTest(corrupted, plt + 2);
            if (segment_length < 4) return error.InvalidPlt;
            const last_length_byte = plt + 2 + @as(usize, segment_length) - 1;
            if ((corrupted[last_length_byte] & 0x7f) == 0x7f) {
                corrupted[last_length_byte] -= 1;
            } else {
                corrupted[last_length_byte] += 1;
            }
            try std.testing.expectError(
                codestream.CodestreamError.InvalidCodestream,
                codestream.analyzeLosslessTemporary(corrupted),
            );
        }

        // Truncating inside the final tile-part payload must surface as a
        // bounded error, never a panic or out-of-bounds read.
        {
            try std.testing.expectError(
                codestream.CodestreamError.TruncatedData,
                codestream.decodeLosslessTemporary(allocator, bytes[0 .. bytes.len - 6]),
            );
        }

        // Flipping payload bytes just past the first SOD must terminate with a
        // bounded error or a safe wrong-decode on every offset, and at least
        // one flip must be actively rejected (the terminated per-pass segment
        // machinery is exercised, not the continuous path).
        {
            const first_sod = findMarker(bytes, codestream.markerValue("sod")) orelse return error.MissingSod;
            var rejected = false;
            var offset = first_sod + 2;
            while (offset < first_sod + 20 and offset < bytes.len) : (offset += 1) {
                const corrupted = try allocator.dupe(u8, bytes);
                defer allocator.free(corrupted);
                corrupted[offset] ^= 0x5a;
                if (codestream.decodeLosslessTemporary(allocator, corrupted)) |decoded_image| {
                    var owned = decoded_image;
                    owned.deinit();
                } else |_| {
                    rejected = true;
                }
            }
            try std.testing.expect(rejected);
        }
    }
}

test "mct none codes components independently and roundtrips losslessly" {
    const allocator = std.testing.allocator;
    const width = 16;
    const height = 16;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const no_mct = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2, .mct = .none });
    defer allocator.free(no_mct);
    const rct = try codestream.encodeLosslessWithOptions(allocator, rgb, .{ .levels = 2, .mct = .rct });
    defer allocator.free(rct);

    // The COD MCT field (segment byte 4, i.e. cod + 8) advertises 0 (none) vs
    // 1 (RCT). The 2-byte marker and 2-byte length precede the segment body.
    const no_mct_cod = findMarker(no_mct, codestream.markerValue("cod")) orelse return error.MissingCod;
    const rct_cod = findMarker(rct, codestream.markerValue("cod")) orelse return error.MissingCod;
    try std.testing.expectEqual(@as(u8, 0), no_mct[no_mct_cod + 8]);
    try std.testing.expectEqual(@as(u8, 1), rct[rct_cod + 8]);

    // Skipping the color transform changes the coded payload.
    try std.testing.expect(!std.mem.eql(u8, no_mct, rct));

    // Both reconstruct the source image byte-exactly (lossless oracle).
    var decoded = try codestream.decodeLosslessTemporary(allocator, no_mct);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
}

test "LRCP iterator emits layer-major packets that map back to RPCL slots" {
    const precincts = [_]packet_plan.Precinct{.{ .width = 8, .height = 8 }};
    const plan = try packet_plan.rpclSingleTile(17, 9, 2, 3, 2, &precincts);
    const total = std.math.cast(usize, plan.packets).?;

    var seen = [_]bool{false} ** 64;
    try std.testing.expect(total <= seen.len);

    var iterator = try packet_plan.LrcpIterator.init(plan, 3, 2);
    var count: usize = 0;
    var previous_layer: u16 = 0;
    while (iterator.next()) |packet| {
        try std.testing.expectEqual(@as(u64, count), packet.sequence);
        // Layer is the outermost axis: it never decreases along the stream.
        try std.testing.expect(packet.layer >= previous_layer);
        previous_layer = packet.layer;

        // Every LRCP packet maps to a distinct RPCL slot with the same identity.
        const slot = try packet_plan.rpclSequenceForPacket(plan, 3, 2, packet);
        const index = std.math.cast(usize, slot).?;
        try std.testing.expect(index < total);
        try std.testing.expect(!seen[index]);
        seen[index] = true;

        const rpcl_packet = (try packet_plan.rpclPacketAt(plan, 3, 2, slot)).?;
        try std.testing.expectEqual(rpcl_packet.resolution, packet.resolution);
        try std.testing.expectEqual(rpcl_packet.precinct_index, packet.precinct_index);
        try std.testing.expectEqual(rpcl_packet.component, packet.component);
        try std.testing.expectEqual(rpcl_packet.layer, packet.layer);
        count += 1;
    }
    try std.testing.expectEqual(total, count);
    for (seen[0..total]) |slot_seen| try std.testing.expect(slot_seen);
}

test "RLCP iterator emits resolution-major layer-second packets that map back to RPCL slots" {
    const precincts = [_]packet_plan.Precinct{.{ .width = 8, .height = 8 }};
    const plan = try packet_plan.rpclSingleTile(17, 9, 2, 3, 2, &precincts);
    const total = std.math.cast(usize, plan.packets).?;

    var seen = [_]bool{false} ** 64;
    try std.testing.expect(total <= seen.len);

    var iterator = try packet_plan.RlcpIterator.init(plan, 3, 2);
    var count: usize = 0;
    var previous_resolution: u8 = 0;
    var previous_layer: u16 = 0;
    while (iterator.next()) |packet| {
        try std.testing.expectEqual(@as(u64, count), packet.sequence);
        // Resolution is outermost, layer second: resolution never decreases,
        // and within one resolution the layer never decreases.
        try std.testing.expect(packet.resolution >= previous_resolution);
        if (packet.resolution > previous_resolution) previous_layer = 0;
        try std.testing.expect(packet.layer >= previous_layer);
        previous_resolution = packet.resolution;
        previous_layer = packet.layer;

        const slot = try packet_plan.rpclSequenceForPacket(plan, 3, 2, packet);
        const index = std.math.cast(usize, slot).?;
        try std.testing.expect(index < total);
        try std.testing.expect(!seen[index]);
        seen[index] = true;

        const rpcl_packet = (try packet_plan.rpclPacketAt(plan, 3, 2, slot)).?;
        try std.testing.expectEqual(rpcl_packet.resolution, packet.resolution);
        try std.testing.expectEqual(rpcl_packet.precinct_index, packet.precinct_index);
        try std.testing.expectEqual(rpcl_packet.component, packet.component);
        try std.testing.expectEqual(rpcl_packet.layer, packet.layer);
        count += 1;
    }
    try std.testing.expectEqual(total, count);
    for (seen[0..total]) |slot_seen| try std.testing.expect(slot_seen);
}

test "position-ordered packet sequences cover all RPCL slots in reference-grid order" {
    const allocator = std.testing.allocator;
    const precincts = [_]packet_plan.Precinct{.{ .width = 8, .height = 8 }};
    const plan = try packet_plan.rpclSingleTile(17, 9, 2, 3, 2, &precincts);
    const total = std.math.cast(usize, plan.packets).?;
    const levels: u8 = plan.resolution_count - 1;

    for ([_]packet_plan.PositionOrder{ .pcrl, .cprl }) |order| {
        const sequence = try packet_plan.positionOrderedPackets(allocator, plan, 3, 2, order);
        defer allocator.free(sequence);
        try std.testing.expectEqual(total, sequence.len);

        var seen = [_]bool{false} ** 64;
        try std.testing.expect(total <= seen.len);
        var previous_key: u64 = 0;
        var previous_component: u16 = 0;
        for (sequence, 0..) |packet, index| {
            try std.testing.expectEqual(@as(u64, index), packet.sequence);

            // The position key (y_ref, x_ref packed) never decreases within
            // one component run for CPRL, or globally for PCRL.
            const resolution = plan.resolutions[packet.resolution];
            const shift: u6 = @intCast(levels - packet.resolution);
            const x_ref = (@as(u64, packet.precinct_x) * resolution.precinct_width) << shift;
            const y_ref = (@as(u64, packet.precinct_y) * resolution.precinct_height) << shift;
            const key = (y_ref << 32) | x_ref;
            switch (order) {
                .pcrl => try std.testing.expect(key >= previous_key),
                .cprl => {
                    try std.testing.expect(packet.component >= previous_component);
                    if (packet.component == previous_component) {
                        try std.testing.expect(key >= previous_key);
                    } else {
                        previous_key = 0;
                    }
                    previous_component = packet.component;
                },
            }
            previous_key = key;

            // Every packet identity maps to a distinct RPCL slot.
            const slot = try packet_plan.rpclSequenceForPacket(plan, 3, 2, packet);
            const slot_index = std.math.cast(usize, slot).?;
            try std.testing.expect(slot_index < total);
            try std.testing.expect(!seen[slot_index]);
            seen[slot_index] = true;
        }
        for (seen[0..total]) |slot_seen| try std.testing.expect(slot_seen);
    }
}

test "permuted progression orders roundtrip losslessly and permute the RPCL packet stream" {
    const allocator = std.testing.allocator;
    const width = 32;
    const height = 32;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..width * height) |i| {
        samples[i * 3 + 0] = @as(u16, @intCast((i * 37) % 256));
        samples[i * 3 + 1] = @as(u16, @intCast((i * 53 + 17) % 256));
        samples[i * 3 + 2] = @as(u16, @intCast((i * 91 + 5) % 256));
    }

    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const PermutedCase = struct {
        progression: codestream.ProgressionOrder,
        cod_byte: u8,
    };
    const permuted_cases = [_]PermutedCase{
        .{ .progression = .lrcp, .cod_byte = 0 },
        .{ .progression = .rlcp, .cod_byte = 1 },
        .{ .progression = .pcrl, .cod_byte = 3 },
        .{ .progression = .cprl, .cod_byte = 4 },
    };

    // 8x8 precincts with 4x4 blocks give several precincts per resolution, so
    // the permuted orders genuinely interleave the stream differently.
    for ([_]u16{ 1, 3 }) |layers| {
        const base = codestream.LosslessOptions{
            .levels = 2,
            .layers = layers,
            .block_width = 4,
            .block_height = 4,
            .precincts = [_]codestream.PrecinctSize{.{ .width = 8, .height = 8 }} ** 33,
            .precinct_count = 1,
        };
        const rpcl = try codestream.encodeLosslessWithOptions(allocator, rgb, base);
        defer allocator.free(rpcl);
        const rpcl_cod = findMarker(rpcl, codestream.markerValue("cod")) orelse return error.MissingCod;
        try std.testing.expectEqual(@as(u8, 2), rpcl[rpcl_cod + 5]);

        var decoded_rpcl = try codestream.decodeLosslessTemporary(allocator, rpcl);
        defer decoded_rpcl.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded_rpcl.samples);

        for (permuted_cases) |scenario| {
            errdefer std.debug.print("permuted progression case failed: {s} layers {}\n", .{ scenario.progression.label(), layers });
            var permuted_options = base;
            permuted_options.progression = scenario.progression;

            const permuted = try codestream.encodeLosslessWithOptions(allocator, rgb, permuted_options);
            defer allocator.free(permuted);

            // The COD progression byte advertises the requested order.
            const permuted_cod = findMarker(permuted, codestream.markerValue("cod")) orelse return error.MissingCod;
            try std.testing.expectEqual(scenario.cod_byte, permuted[permuted_cod + 5]);

            // The permuted packet order produces a different stream.
            try std.testing.expect(!std.mem.eql(u8, permuted, rpcl));

            // The permuted stream reconstructs the source byte-exactly.
            var decoded = try codestream.decodeLosslessTemporary(allocator, permuted);
            defer decoded.deinit();
            try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
        }
    }
}

fn makeMultiTileTestImage(allocator: std.mem.Allocator, width: usize, height: usize) ![]u16 {
    const samples = try allocator.alloc(u16, width * height * 3);
    for (0..height) |y| {
        for (0..width) |x| {
            const base = (y * width + x) * 3;
            samples[base + 0] = @intCast((17 + x * 19 + y * 31) & 0xff);
            samples[base + 1] = @intCast((71 + x * 7 + y * 13) & 0xff);
            samples[base + 2] = @intCast((139 + x * 23 + y * 5) & 0xff);
        }
    }
    return samples;
}

// Multi-tile fixture geometry: 8x8 precincts with 4x4 blocks satisfy the ISO
// B.7 bound (blocks never cross precinct boundaries: 8 >= 4 at resolution 0,
// 8/2 >= 4 above it). Most existing tests retain one part per tile; dedicated
// tests opt into resolution divisions.
const multi_tile_test_options = codestream.LosslessOptions{
    .levels = 2,
    .tile_width = 32,
    .tile_height = 32,
    .block_width = 4,
    .block_height = 4,
    .precincts = [_]codestream.PrecinctSize{.{ .width = 8, .height = 8 }} ** 33,
    .precinct_count = 1,
    .tile_part_divisions = null,
};

test "multi-tile encode emits row-major single-part tiles with TLM" {
    const allocator = std.testing.allocator;
    // 48x48 with 32x32 tiles: a 2x2 grid whose right/bottom tiles are 16-wide
    // edge tiles. Every tile achieves the global two decomposition levels.
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, multi_tile_test_options);
    defer allocator.free(bytes);

    // SIZ advertises the real tile grid.
    const siz = findMarker(bytes, codestream.markerValue("siz")) orelse return error.MissingSiz;
    try std.testing.expectEqual(@as(u32, width), readU32BeTest(bytes, siz + 6));
    try std.testing.expectEqual(@as(u32, height), readU32BeTest(bytes, siz + 10));
    try std.testing.expectEqual(@as(u32, 32), readU32BeTest(bytes, siz + 22));
    try std.testing.expectEqual(@as(u32, 32), readU32BeTest(bytes, siz + 26));

    // One TLM segment with four entries (Ttlm u16 + Ptlm u32 each).
    const tlm = findMarker(bytes, codestream.markerValue("tlm")) orelse return error.MissingTlm;
    try std.testing.expectEqual(@as(u16, 4 + 4 * 6), readU16BeTest(bytes, tlm + 2));

    // Four SOT markers: row-major Isot 0..3, TPsot = 0, TNsot = 1, and each
    // Psot chains exactly to the next SOT (the last one to EOC).
    try std.testing.expectEqual(@as(usize, 4), countMarker(bytes, codestream.markerValue("sot")));
    var sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    for (0..4) |tile_index| {
        try std.testing.expectEqual(@as(u16, 10), readU16BeTest(bytes, sot + 2));
        try std.testing.expectEqual(@as(u16, @intCast(tile_index)), readU16BeTest(bytes, sot + 4));
        const psot = readU32BeTest(bytes, sot + 6);
        try std.testing.expectEqual(@as(u8, 0), bytes[sot + 10]);
        try std.testing.expectEqual(@as(u8, 1), bytes[sot + 11]);
        const next = sot + @as(usize, psot);
        if (tile_index < 3) {
            try std.testing.expectEqual(codestream.markerValue("sot"), readU16BeTest(bytes, next));
            sot = next;
        } else {
            try std.testing.expectEqual(codestream.markerValue("eoc"), readU16BeTest(bytes, next));
            try std.testing.expectEqual(bytes.len, next + 2);
        }
    }

    // Encoding is deterministic across worker counts.
    var threaded_options = multi_tile_test_options;
    threaded_options.threads = 3;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    // The JP2 wrapper accepts the multi-tile SIZ.
    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
    defer allocator.free(wrapped);
    const info = try jp2.parseInfo(wrapped);
    try std.testing.expectEqual(@as(usize, width), info.width);

    // Stage C: the strict decoder reconstructs the multi-tile stream
    // byte-exactly (lossless oracle).
    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
}

test "multi-tile RPCL resolution tile-parts roundtrip with continuous T2 state" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = multi_tile_test_options;
    options.layers = 3;
    options.tile_part_divisions = 'R';
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    const parts_per_tile: usize = options.levels + 1;
    const total_parts = 4 * parts_per_tile;
    try std.testing.expectEqual(total_parts, countMarker(bytes, codestream.markerValue("sot")));
    const tlm = findMarker(bytes, codestream.markerValue("tlm")) orelse return error.MissingTlm;
    try std.testing.expectEqual(@as(u16, @intCast(4 + total_parts * 6)), readU16BeTest(bytes, tlm + 2));

    var sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    for (0..4) |tile_index| {
        for (0..parts_per_tile) |resolution| {
            try std.testing.expectEqual(@as(u16, @intCast(tile_index)), readU16BeTest(bytes, sot + 4));
            try std.testing.expectEqual(@as(u8, @intCast(resolution)), bytes[sot + 10]);
            try std.testing.expectEqual(@as(u8, @intCast(parts_per_tile)), bytes[sot + 11]);
            const next = sot + @as(usize, readU32BeTest(bytes, sot + 6));
            if (tile_index + 1 == 4 and resolution + 1 == parts_per_tile) {
                try std.testing.expectEqual(codestream.markerValue("eoc"), readU16BeTest(bytes, next));
                try std.testing.expectEqual(bytes.len, next + 2);
            } else {
                try std.testing.expectEqual(codestream.markerValue("sot"), readU16BeTest(bytes, next));
                sot = next;
            }
        }
    }

    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    const second_sot = first_sot + @as(usize, readU32BeTest(bytes, first_sot + 6));
    const second_sod = findMarkerAfter(bytes, codestream.markerValue("sod"), second_sot) orelse return error.MissingSod;
    try std.testing.expectEqual(codestream.markerValue("sop"), readU16BeTest(bytes, second_sod + 2));
    // Tile 0 R0 has one precinct x three components x three layers.
    try std.testing.expectEqual(@as(u16, 9), readU16BeTest(bytes, second_sod + 6));

    const stats = try codestream.analyzeLosslessTemporary(bytes);
    try std.testing.expectEqual(@as(?u8, 'R'), stats.tile_part_divisions);
    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
    defer allocator.free(wrapped);
    const info = try jp2.parseInfo(wrapped);
    try std.testing.expectEqual(@as(u32, width), info.width);

    var threaded_options = options;
    threaded_options.threads = 4;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    var marker_light_options = options;
    marker_light_options.tlm = false;
    marker_light_options.sop = false;
    marker_light_options.eph = false;
    const marker_light = try codestream.encodeLosslessWithOptions(allocator, rgb, marker_light_options);
    defer allocator.free(marker_light);
    const marker_light_sot = findMarker(marker_light, codestream.markerValue("sot")) orelse return error.MissingSot;
    const marker_light_tlm = findMarker(marker_light[0..marker_light_sot], codestream.markerValue("tlm"));
    try std.testing.expect(marker_light_tlm == null);
    const marker_light_cod = findMarker(marker_light[0..marker_light_sot], codestream.markerValue("cod")) orelse return error.MissingCod;
    try std.testing.expectEqual(@as(u8, 0), marker_light[marker_light_cod + 4] & 0x06);
    var marker_light_decoded = try codestream.decodeLosslessTemporary(allocator, marker_light);
    defer marker_light_decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, marker_light_decoded.samples);
}

test "multi-tile resolution tile-parts reject inconsistent SOT state" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };
    var options = multi_tile_test_options;
    options.tile_part_divisions = 'R';
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    const second_sot = findMarkerAfter(bytes, codestream.markerValue("sot"), first_sot + 2) orelse return error.MissingSot;
    {
        const corrupted = try allocator.dupe(u8, bytes);
        defer allocator.free(corrupted);
        corrupted[second_sot + 10] = 2;
        try std.testing.expectError(
            codestream.CodestreamError.InvalidCodestream,
            codestream.analyzeLosslessTemporary(corrupted),
        );
    }
    {
        const corrupted = try allocator.dupe(u8, bytes);
        defer allocator.free(corrupted);
        corrupted[second_sot + 11] = 2;
        try std.testing.expectError(
            codestream.CodestreamError.InvalidCodestream,
            codestream.analyzeLosslessTemporary(corrupted),
        );
    }
}

