test "multi-tile irreversible 9/7 roundtrips within lossy tolerance" {
    // The irreversible tile front end (ICT + 9/7 + deadzone quantization)
    // hooks into the transform-agnostic tile pipeline, with per-band Mb
    // taken from the signalled irreversible step exponents. Origin-aware
    // lifting retains reference-grid parity for aligned and odd-origin tiles.
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    for (0..height) |y| {
        for (0..width) |x| {
            const i = (y * width + x) * 3;
            samples[i + 0] = @intCast((x * 4) % 256);
            samples[i + 1] = @intCast((y * 4) % 256);
            samples[i + 2] = @intCast((x * 2 + y * 2) % 256);
        }
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const Scenario = struct { label: []const u8, quantization: codestream.QuantizationStyle };
    const scenarios = [_]Scenario{
        .{ .label = "scalar-expounded", .quantization = .scalar_expounded },
        .{ .label = "scalar-derived", .quantization = .scalar_derived },
    };
    for (scenarios) |scenario| {
        errdefer std.debug.print("multi-tile 9/7 scenario failed: {s}\n", .{scenario.label});
        var options = multi_tile_test_options;
        options.transform = .irreversible_9_7;
        options.mct = .ict;
        options.quantization = scenario.quantization;
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
        defer allocator.free(bytes);

        try std.testing.expectEqual(@as(usize, 4), countMarker(bytes, codestream.markerValue("sot")));
        const cod = findMarker(bytes, codestream.markerValue("cod")) orelse return error.MissingCod;
        // SPcod transform byte 0x00 = irreversible 9/7.
        try std.testing.expectEqual(@as(u8, 0x00), bytes[cod + 13]);

        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        var max_diff: i32 = 0;
        for (samples, decoded.samples) |expected, actual| {
            const diff = @as(i32, expected) - @as(i32, actual);
            max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
        }
        try std.testing.expect(max_diff <= 8);

        var threaded_decode = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{ .threads = 3 });
        defer threaded_decode.deinit();
        try std.testing.expectEqualSlices(u16, decoded.samples, threaded_decode.samples);

        var threaded_options = options;
        threaded_options.threads = 3;
        const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
        defer allocator.free(threaded);
        try std.testing.expectEqualSlices(u8, bytes, threaded);

        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
        defer allocator.free(wrapped);
        const info = try jp2.parseInfo(wrapped);
        try std.testing.expectEqual(@as(usize, width), info.width);
    }

    // Rate-targeted 9/7 tiles use the 9/7 PCRD weight table (squared
    // reconstruction step x 9/7 norm) in the global cross-tile allocation.
    // The final layer always carries the complete stream, so the full
    // decode still reconstructs within lossy tolerance, and the per-layer
    // PLT byte sums grow monotonically toward the total payload.
    {
        var options = multi_tile_test_options;
        options.transform = .irreversible_9_7;
        options.mct = .ict;
        options.quantization = .scalar_expounded;
        options.progression = .lrcp;
        options.layers = 3;
        options.rates[0] = 20.0;
        options.rates[1] = 10.0;
        options.rates[2] = 1.0;
        options.rate_count = 3;
        options.sop = false;
        options.tlm = false;
        options.tile_part_divisions = null;
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
        defer allocator.free(bytes);

        // Deterministic across encode threads.
        var threaded_options = options;
        threaded_options.threads = 3;
        const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
        defer allocator.free(threaded);
        try std.testing.expectEqualSlices(u8, bytes, threaded);

        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        var max_diff: i32 = 0;
        for (samples, decoded.samples) |expected, actual| {
            const diff = @as(i32, expected) - @as(i32, actual);
            max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
        }
        try std.testing.expect(max_diff <= 8);

        // Per-layer PLT byte totals (LRCP keeps the layer outermost inside a
        // tile), aggregated across all four tiles: the coarse first layer
        // targeted at ratio 20 must carry fewer bytes than the lossless
        // final layer targeted at ratio 1.
        var layer_bytes = [_]u64{ 0, 0, 0 };
        {
            const sot = codestream.markerValue("sot");
            const sod = codestream.markerValue("sod");
            const plt_marker = codestream.markerValue("plt");
            var cursor: usize = 2;
            while (readU16BeTest(bytes, cursor) != sot) {
                cursor += 2 + readU16BeTest(bytes, cursor + 2);
            }
            var tiles_seen: usize = 0;
            while (tiles_seen < 4) : (tiles_seen += 1) {
                const psot = readU32BeTest(bytes, cursor + 6);
                var lengths: std.ArrayList(u64) = .empty;
                defer lengths.deinit(allocator);
                var header_cursor = cursor + 12;
                while (readU16BeTest(bytes, header_cursor) != sod) {
                    const segment_length = readU16BeTest(bytes, header_cursor + 2);
                    if (readU16BeTest(bytes, header_cursor) == plt_marker) {
                        var value: u64 = 0;
                        for (bytes[header_cursor + 5 .. header_cursor + 2 + segment_length]) |byte| {
                            value = (value << 7) | (byte & 0x7f);
                            if ((byte & 0x80) == 0) {
                                try lengths.append(allocator, value);
                                value = 0;
                            }
                        }
                    }
                    header_cursor += 2 + segment_length;
                }
                try std.testing.expectEqual(@as(usize, 0), lengths.items.len % 3);
                const per_layer = lengths.items.len / 3;
                for (0..3) |layer| {
                    for (lengths.items[layer * per_layer ..][0..per_layer]) |len| layer_bytes[layer] += len;
                }
                cursor += psot;
            }
        }
        try std.testing.expect(layer_bytes[0] > 0);
        try std.testing.expect(layer_bytes[2] > layer_bytes[0]);
    }

    // The 17x17 grid exercises odd first-level parity and odd parity after
    // origin reduction at deeper levels.
    {
        var options = multi_tile_test_options;
        options.transform = .irreversible_9_7;
        options.mct = .ict;
        options.quantization = .scalar_expounded;
        options.tile_width = 17;
        options.tile_height = 17;
        const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
        defer allocator.free(bytes);

        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        var max_diff: i32 = 0;
        for (samples, decoded.samples) |expected, actual| {
            const diff = @as(i32, expected) - @as(i32, actual);
            max_diff = @max(max_diff, @as(i32, @intCast(@abs(diff))));
        }
        try std.testing.expect(max_diff <= 8);

        options.threads = 3;
        const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
        defer allocator.free(threaded);
        try std.testing.expectEqualSlices(u8, bytes, threaded);

        const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
        defer allocator.free(wrapped);
        const info = try jp2.parseInfo(wrapped);
        try std.testing.expectEqual(@as(u32, width), info.width);
        try std.testing.expectEqual(@as(u32, height), info.height);
    }
}

test "multi-tile layer tile-part divisions emit one part per layer per tile" {
    // `--tile-parts L` with LRCP: the layer is the outermost packet loop in
    // every tile, so each tile splits into `layers` tile-parts at layer
    // boundaries (TPsot 0..layers-1, TNsot = layers), each part carrying its
    // own PLT for its layer's packets. The stream decodes through the
    // general multi-part tile walk.
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = multi_tile_test_options;
    options.layers = 3;
    options.progression = .lrcp;
    options.tile_part_divisions = 'L';
    options.sop = false;
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    // Walk the tile-part sequence: 4 tiles x 3 layer parts, TPsot in order,
    // per-part PLT covering exactly one layer's packet count.
    {
        const sot = codestream.markerValue("sot");
        const sod = codestream.markerValue("sod");
        const plt_marker = codestream.markerValue("plt");
        var cursor: usize = 2;
        while (readU16BeTest(bytes, cursor) != sot) {
            cursor += 2 + readU16BeTest(bytes, cursor + 2);
        }
        var parts_seen: usize = 0;
        var per_layer_packets: ?usize = null;
        while (readU16BeTest(bytes, cursor) == sot) {
            const psot = readU32BeTest(bytes, cursor + 6);
            const tile_part_index = bytes[cursor + 10];
            const tile_part_count = bytes[cursor + 11];
            try std.testing.expectEqual(@as(u8, 3), tile_part_count);
            try std.testing.expectEqual(@as(u8, @intCast(parts_seen % 3)), tile_part_index);

            var packet_count: usize = 0;
            var header_cursor = cursor + 12;
            while (readU16BeTest(bytes, header_cursor) != sod) {
                const segment_length = readU16BeTest(bytes, header_cursor + 2);
                if (readU16BeTest(bytes, header_cursor) == plt_marker) {
                    for (bytes[header_cursor + 5 .. header_cursor + 2 + segment_length]) |byte| {
                        if ((byte & 0x80) == 0) packet_count += 1;
                    }
                }
                header_cursor += 2 + segment_length;
            }
            try std.testing.expect(packet_count > 0);
            if (per_layer_packets) |expected| {
                try std.testing.expectEqual(expected, packet_count);
            } else {
                per_layer_packets = packet_count;
            }

            parts_seen += 1;
            cursor += psot;
            if (cursor + 1 >= bytes.len) break;
        }
        try std.testing.expectEqual(@as(usize, 12), parts_seen);
    }

    // Lossless decode through the general multi-part walk, single- and
    // multi-threaded, plus deterministic re-encode and JP2 acceptance.
    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
    var threaded_decode = try codestream.decodeLosslessTemporaryWithOptions(allocator, bytes, .{ .threads = 3 });
    defer threaded_decode.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, threaded_decode.samples);

    var threaded_options = options;
    threaded_options.threads = 3;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    const wrapped = try jp2.wrapRgbCodestream(allocator, rgb, bytes);
    defer allocator.free(wrapped);
    const info = try jp2.parseInfo(wrapped);
    try std.testing.expectEqual(@as(usize, width), info.width);

    // L-divisions need LRCP; RPCL keeps the resolution outermost, so the
    // combination fails closed.
    var rpcl_options = options;
    rpcl_options.progression = .rpcl;
    try std.testing.expectError(
        codestream.CodestreamError.UnsupportedPayload,
        codestream.encodeLosslessWithOptions(allocator, rgb, rpcl_options),
    );

    // The single-tile assembler emits one part for `L` (normalized), keeping
    // the narrow path unaffected.
    var single_options = options;
    single_options.tile_width = 4096;
    single_options.tile_height = 4096;
    single_options.precincts = multi_tile_test_options.precincts;
    const single = try codestream.encodeLosslessWithOptions(allocator, rgb, single_options);
    defer allocator.free(single);
    try std.testing.expectEqual(@as(usize, 1), countMarker(single, codestream.markerValue("sot")));
    var single_decoded = try codestream.decodeLosslessTemporary(allocator, single);
    defer single_decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, single_decoded.samples);
}

test "multi-tile rate targets allocate one global budget across tiles" {
    // Four 32x32 tiles with strongly heterogeneous content: tile 0 carries
    // high-amplitude noise, the others a shallow gradient. The global PCRD
    // pass (applyGridPcrdTargets) spends one slope threshold over every
    // block of every tile, so the cumulative layer-1 size must land on the
    // whole-image byte target while individual tiles deviate from the
    // proportional per-tile split the old tile-local allocation produced.
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try allocator.alloc(u16, width * height * 3);
    defer allocator.free(samples);
    var seed: u32 = 12345;
    for (0..height) |y| {
        for (0..width) |x| {
            const i = (y * width + x) * 3;
            if (x < 32 and y < 32) {
                seed = seed *% 1664525 +% 1013904223;
                samples[i + 0] = @intCast((seed >> 8) & 0xff);
                samples[i + 1] = @intCast((seed >> 16) & 0xff);
                samples[i + 2] = @intCast((seed >> 24) & 0xff);
            } else {
                samples[i + 0] = @intCast(96 + ((x >> 2) & 15));
                samples[i + 1] = @intCast(112 + ((y >> 2) & 15));
                samples[i + 2] = @intCast(128 + (((x + y) >> 3) & 7));
            }
        }
    }
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = multi_tile_test_options;
    options.layers = 2;
    options.progression = .lrcp;
    options.rate_count = 2;
    options.rates[0] = 8.0;
    options.rates[1] = 1.0;
    options.sop = false;
    options.tlm = false;
    options.tile_part_divisions = null;
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    // Lossless final layer, deterministic across encode threads.
    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
    var threaded_options = options;
    threaded_options.threads = 3;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    // Measure the allocation at the artifact level (block payload bytes,
    // before packet-header framing): the layer targets reference the
    // compressed block payload, so the catalog truncations are the exact
    // quantity the allocator budgets.
    const grid = try tile_grid.Grid.fromImageSize(width, height, 32, 32);
    const precincts = [_]packet_plan.Precinct{.{ .width = 8, .height = 8 }};
    var grid_options = tile_pipeline.PacketScaffoldOptions{
        .layers = 2,
        .block_width = 4,
        .block_height = 4,
        .precincts = &precincts,
        .packet_order = .lrcp,
    };
    grid_options.rates[0] = 8.0;
    grid_options.rates[1] = 1.0;
    grid_options.rate_count = 2;
    var artifacts = try tile_pipeline.buildTileGridRpclEncodeArtifactsIsoMq(
        allocator,
        rgb,
        grid,
        2,
        grid_options,
        .{},
    );
    defer artifacts.deinit();
    try std.testing.expectEqual(@as(usize, 4), artifacts.tiles.len);

    var tile_layer0 = [_]u64{0} ** 4;
    var tile_total = [_]u64{0} ** 4;
    for (artifacts.tiles, 0..) |tile, tile_index| {
        for (tile.catalog.blocks) |encoded| {
            tile_layer0[tile_index] += encoded.layers[0].cumulative_bytes;
            tile_total[tile_index] += encoded.segment.byte_length;
        }
    }

    var total_layer0: u64 = 0;
    var total_payload: u64 = 0;
    for (tile_layer0) |value| total_layer0 += value;
    for (tile_total) |value| total_payload += value;
    try std.testing.expect(total_layer0 > 0);

    // The cumulative first-layer payload lands on the global byte target
    // (total compressed payload / 8), never exceeding it and staying within
    // pass-snapping tolerance below it.
    const target = @as(f64, @floatFromInt(total_payload)) / 8.0;
    const actual = @as(f64, @floatFromInt(total_layer0));
    errdefer std.debug.print(
        "global layer-0 {} vs target {d:.0} (payload {}); per tile layer0 {any} total {any}\n",
        .{ total_layer0, target, total_payload, tile_layer0, tile_total },
    );
    try std.testing.expect(actual <= target + 1.0);
    try std.testing.expect(actual >= target * 0.7);

    // One global slope threshold: with this heterogeneous content at least
    // one tile must deviate clearly from its own proportional /8 share,
    // which is exactly what the old tile-local allocation pinned.
    var deviated = false;
    for (tile_layer0, tile_total) |layer0, total| {
        if (total == 0) continue;
        const share = @as(f64, @floatFromInt(total)) / 8.0;
        if (@abs(@as(f64, @floatFromInt(layer0)) - share) > share * 0.25) deviated = true;
    }
    try std.testing.expect(deviated);
}

test "multi-tile rate-targeted quality layers roundtrip deterministically" {
    const allocator = std.testing.allocator;
    const width = 64;
    const height = 64;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = multi_tile_test_options;
    options.layers = 3;
    options.progression = .lrcp;
    options.rate_count = 2;
    options.rates[0] = 16.0;
    options.rates[1] = 4.0;
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    var even_options = options;
    even_options.rate_count = 0;
    @memset(&even_options.rates, 0);
    const even = try codestream.encodeLosslessWithOptions(allocator, rgb, even_options);
    defer allocator.free(even);
    try std.testing.expect(!std.mem.eql(u8, even, bytes));

    const cod = findMarker(bytes, codestream.markerValue("cod")) orelse return error.MissingCod;
    try std.testing.expectEqual(@as(u16, 3), readU16BeTest(bytes, cod + 6));
    try std.testing.expectEqual(@as(u8, 0), bytes[cod + 12]);
    try std.testing.expectEqual(@as(usize, 4), countMarker(bytes, codestream.markerValue("sot")));

    var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
    defer decoded.deinit();
    try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);

    var threaded_options = options;
    threaded_options.threads = 3;
    const threaded = try codestream.encodeLosslessWithOptions(allocator, rgb, threaded_options);
    defer allocator.free(threaded);
    try std.testing.expectEqualSlices(u8, bytes, threaded);

    const packet_lengths = try collectCodestreamPltLengthsForTest(allocator, bytes);
    defer allocator.free(packet_lengths);
    try std.testing.expectEqual(@as(usize, 0), packet_lengths.len % @as(usize, options.layers));
    var early_bytes: u64 = 0;
    var final_bytes: u64 = 0;
    for (packet_lengths, 0..) |length, index| {
        if (index % options.layers == options.layers - 1) {
            final_bytes += length;
        } else {
            early_bytes += length;
        }
    }
    try std.testing.expect(early_bytes > 0);
    try std.testing.expect(final_bytes > 0);
}

