test "multi-tile terminate-all fails closed on packet corruption" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    var options = multi_tile_test_options;
    options.terminate_all = true;
    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, options);
    defer allocator.free(bytes);

    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    const second_sot = findMarkerAfter(bytes, codestream.markerValue("sot"), first_sot + 2) orelse return error.MissingSot;
    const second_plt = findMarkerAfter(bytes, codestream.markerValue("plt"), second_sot) orelse return error.MissingPlt;
    const second_sod = findMarkerAfter(bytes, codestream.markerValue("sod"), second_sot) orelse return error.MissingSod;
    try std.testing.expect(second_plt < second_sod);

    // Sanity: the clean stream reconstructs through the strict multi-tile
    // TERMALL path before corruptions are applied.
    {
        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, samples, decoded.samples);
    }

    // Corrupt the second tile's PLT packet-length byte. The tile-part payload
    // span no longer matches the packet table, so the SOT/PLT walk must reject
    // it before any unchecked packet payload access is possible.
    {
        const corrupted = try allocator.dupe(u8, bytes);
        defer allocator.free(corrupted);
        const segment_length = readU16BeTest(corrupted, second_plt + 2);
        if (segment_length < 4) return error.InvalidPlt;
        const last_length_byte = second_plt + 2 + @as(usize, segment_length) - 1;
        corrupted[last_length_byte] ^= 0x01;
        try std.testing.expectError(
            codestream.CodestreamError.InvalidCodestream,
            codestream.decodeLosslessTemporary(allocator, corrupted),
        );
    }

    // Truncating inside the final tile-part payload remains a bounded
    // truncation error, even with one terminated segment per coding pass.
    try std.testing.expectError(
        codestream.CodestreamError.TruncatedData,
        codestream.decodeLosslessTemporary(allocator, bytes[0 .. bytes.len - 8]),
    );

    // Walk payload flips in the second tile's SOD payload. Some corruptions may
    // still decode to wrong pixels, but the decoder must never panic/OOB and at
    // least one offset should be actively rejected by the per-pass segment path.
    var rejected = false;
    var offset = second_sod + 2;
    while (offset < second_sod + 32 and offset < bytes.len) : (offset += 1) {
        const corrupted = try allocator.dupe(u8, bytes);
        defer allocator.free(corrupted);
        corrupted[offset] ^= 0x5a;
        if (codestream.decodeLosslessTemporary(allocator, corrupted)) |decoded_image| {
            var owned = decoded_image;
            owned.deinit();
        } else |_| {
            rejected = true;
        }
    }
    try std.testing.expect(rejected);
}

test "multi-tile encode fails closed outside the bounded envelope" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const Case = struct {
        label: []const u8,
        mutate: *const fn (options: *codestream.LosslessOptions) void,
    };
    const cases = [_]Case{
        .{ .label = "mct none", .mutate = struct {
            fn mutate(options: *codestream.LosslessOptions) void {
                options.mct = .none;
            }
        }.mutate },
        .{ .label = "bypass without terminate-all", .mutate = struct {
            fn mutate(options: *codestream.LosslessOptions) void {
                options.bypass = true;
            }
        }.mutate },
        .{ .label = "debug sidecar", .mutate = struct {
            fn mutate(options: *codestream.LosslessOptions) void {
                options.emit_temporary_payload_sidecar = true;
            }
        }.mutate },
        // Irreversible 9/7 multi-tile encode (ICT + scalar quantization,
        // including rate targets) is supported now; its roundtrips live in
        // "multi-tile irreversible 9/7 roundtrips within lossy tolerance".
        // 9/7 without ICT stays fail-closed (the front end always uses ICT).
        .{ .label = "lossy 9/7 without ICT", .mutate = struct {
            fn mutate(options: *codestream.LosslessOptions) void {
                options.transform = .irreversible_9_7;
                options.mct = .rct;
                options.quantization = .scalar_expounded;
            }
        }.mutate },
        .{ .label = "resolution tile-parts with non-RPCL progression", .mutate = struct {
            fn mutate(options: *codestream.LosslessOptions) void {
                options.tile_part_divisions = 'R';
                options.progression = .lrcp;
            }
        }.mutate },
        .{
            .label = "tile cannot carry the global DWT level count",
            .mutate = struct {
                fn mutate(options: *codestream.LosslessOptions) void {
                    options.tile_width = 2;
                }
            }.mutate,
        },
    };

    for (cases) |scenario| {
        errdefer std.debug.print("multi-tile fail-close case failed: {s}\n", .{scenario.label});
        var options = multi_tile_test_options;
        scenario.mutate(&options);
        try std.testing.expectError(
            codestream.CodestreamError.UnsupportedPayload,
            codestream.encodeLosslessWithOptions(allocator, rgb, options),
        );
    }
}

test "multi-tile decode SOT walk validates the v1 tile-part discipline" {
    const allocator = std.testing.allocator;
    const width = 48;
    const height = 48;
    const samples = try makeMultiTileTestImage(allocator, width, height);
    defer allocator.free(samples);
    const rgb = image.RgbImage{
        .allocator = allocator,
        .width = width,
        .height = height,
        .bit_depth = 8,
        .samples = samples,
    };

    const bytes = try codestream.encodeLosslessWithOptions(allocator, rgb, multi_tile_test_options);
    defer allocator.free(bytes);

    // The intact stream passes the Stage B walk and decodes losslessly.
    {
        var decoded = try codestream.decodeLosslessTemporary(allocator, bytes);
        defer decoded.deinit();
        try std.testing.expectEqualSlices(u16, rgb.samples, decoded.samples);
    }

    const first_sot = findMarker(bytes, codestream.markerValue("sot")) orelse return error.MissingSot;
    const second_sot = findMarkerAfter(bytes, codestream.markerValue("sot"), first_sot + 2) orelse return error.MissingSot;
    const tlm = findMarker(bytes, codestream.markerValue("tlm")) orelse return error.MissingTlm;
    // TLM layout: marker(2) Ltlm(2) Ztlm(1) Stlm(1), then 6-byte entries
    // (Ttlm u16 + Ptlm u32).
    const tlm_entries = tlm + 6;

    const Case = struct {
        label: []const u8,
        expected: anyerror,
        mutate: *const fn (stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void,
    };
    const cases = [_]Case{
        .{
            // SOT says tile 1 where TLM recorded tile 0.
            .label = "SOT Isot contradicts TLM",
            .expected = codestream.CodestreamError.InvalidCodestream,
            .mutate = struct {
                fn mutate(stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void {
                    _ = sot1;
                    _ = tlm_start;
                    stream[sot0 + 5] = 1;
                }
            }.mutate,
        },
        .{
            // Both TLM and SOT claim tile 1 first, creating a duplicate tile
            // later in the stream. True reordered-but-unique tile sequences are
            // accepted for Kakadu interop; duplicates remain structural damage.
            .label = "duplicate tile sequence",
            .expected = codestream.CodestreamError.InvalidCodestream,
            .mutate = struct {
                fn mutate(stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void {
                    _ = sot1;
                    stream[sot0 + 5] = 1;
                    stream[tlm_start + 1] = 1;
                }
            }.mutate,
        },
        .{
            .label = "nonzero TPsot",
            .expected = codestream.CodestreamError.InvalidCodestream,
            .mutate = struct {
                fn mutate(stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void {
                    _ = sot1;
                    _ = tlm_start;
                    stream[sot0 + 10] = 1;
                }
            }.mutate,
        },
        .{
            // Multi-part tile sequences are supported now, but a tile that
            // advertises two parts and never delivers the second stays
            // incomplete at EOC.
            .label = "TNsot advertising two parts without a second part",
            .expected = codestream.CodestreamError.InvalidCodestream,
            .mutate = struct {
                fn mutate(stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void {
                    _ = sot1;
                    _ = tlm_start;
                    stream[sot0 + 11] = 2;
                }
            }.mutate,
        },
        .{
            // Second tile's Psot disagrees with its TLM entry.
            .label = "TLM length mismatch",
            .expected = codestream.CodestreamError.InvalidCodestream,
            .mutate = struct {
                fn mutate(stream: []u8, sot0: usize, sot1: usize, tlm_start: usize) void {
                    _ = sot0;
                    _ = tlm_start;
                    stream[sot1 + 9] +%= 1;
                }
            }.mutate,
        },
    };

    for (cases) |scenario| {
        errdefer std.debug.print("multi-tile SOT walk case failed: {s}\n", .{scenario.label});
        const corrupted = try allocator.dupe(u8, bytes);
        defer allocator.free(corrupted);
        scenario.mutate(corrupted, first_sot, second_sot, tlm_entries);
        try std.testing.expectError(
            scenario.expected,
            codestream.decodeLosslessTemporary(allocator, corrupted),
        );
    }

    // Truncating inside the last tile-part must surface as bounded truncation.
    try std.testing.expectError(
        codestream.CodestreamError.TruncatedData,
        codestream.decodeLosslessTemporary(allocator, bytes[0 .. bytes.len - 8]),
    );
}

