    const decoded_lengths = try decodePltMarkerLengthsForTest(allocator, first_marker);
    defer allocator.free(decoded_lengths);
    try std.testing.expectEqualSlices(u32, try plt.packetLengthsForEntry(0), decoded_lengths);
}

